const samasGroups = Object.entries(samasExamples).map(([title, examples]) => ({ title, rule:title.includes('দ্বন্দ্ব') ? 'দুই বা একাধিক পদের সমান গুরুত্ব থাকলে দ্বন্দ্ব। ব্যাসবাক্যে সাধারণত “ও/এবং” বসে।' : title.includes('তৎপুরুষ') ? 'পরপদের অর্থ প্রধান; ব্যাসবাক্যের বিভক্তিই তৎপুরুষের উপপ্রকার বলে দেয়।' : title.includes('কর্মধারয়') ? 'পূর্বপদ বিশেষণ বা উপমানের মতো পরপদকে বোঝায়; সমস্তপদের অর্থও পরপদেই থাকে।' : title.includes('বহুব্রীহি') ? 'কোনও পদই প্রধান নয়; ব্যাসবাক্যে “যার/যে/যাহার” থাকলে বহুব্রীহির সম্ভাবনা জোরালো।' : 'অব্যয়ের প্রাধান্য থাকে; ব্যাসবাক্যে অনুযায়ী, পর্যন্ত, সমীপে ইত্যাদি থাকে।', examples }));
const samasSection = { id:'samas-rules', title:'সমাসের প্রকারভেদ ও ব্যাসবাক্য', definition:'<b>সমাস</b> হল একাধিক পদের মিলনে সংক্ষিপ্ত নতুন পদ। যে পদটি তৈরি হয় সেটি <b>সমস্তপদ</b>; তার বিস্তৃত ব্যাখ্যা <b>ব্যাসবাক্য</b>; আগে থাকা পদ <b>পূর্বপদ</b> এবং পরে থাকা পদ <b>পরপদ</b>।', groups:samasGroups, tip:'২ সেকেন্ডের ট্রিক: ব্যাসবাক্যে “ও” থাকলে দ্বন্দ্ব, বিভক্তি থাকলে তৎপুরুষ, “যে/যার” থাকলে বহুব্রীহি, আর “যে” বসিয়ে পরপদটি প্রধান হলে কর্মধারয়।', memory:'ও দেখিলে দ্বন্দ্ব ভাই, বিভক্তিতে তৎপুরুষ পাই; যে বা যার বহুব্রীহি, বিশেষণে কর্মধারয় সই।', mistakes:[['রাজপুত্র = রাজা ও পুত্র','রাজপুত্র = রাজার পুত্র (সম্বন্ধ তৎপুরুষ)'],['নীলকণ্ঠ = নীল কণ্ঠ','নীলকণ্ঠ = নীল কণ্ঠ যার (বহুব্রীহি)'],['দিনরাত্রি = দিনের রাত্রি','দিনরাত্রি = দিন ও রাত্রি (দ্বন্দ্ব)'],['পদ্মনয়ন = পদ্মের নয়ন','পদ্মনয়ন = পদ্মের ন্যায় নয়ন যার/যে—প্রসঙ্গ দেখে কর্মধারয় বা বহুব্রীহি'],['ভয়মুক্ত = ভয়ের মুক্ত','ভয়মুক্ত = ভয় থেকে মুক্ত (অপাদান তৎপুরুষ)'],['গৃহবাস = গৃহের বাস','গৃহবাস = গৃহে বাস (অধিকরণ তৎপুরুষ)'],['জলপান = জল দিয়ে পান','জলপান = জলকে পান (কর্ম তৎপুরুষ)'],['চরণকমল = চরণের কমল','চরণকমল = কমলের ন্যায় চরণ (উপমান কর্মধারয়)'],['অকাল = অ-এর কাল','অকাল = না কাল (নঞ তৎপুরুষ)'],['সপরিবার = পরিবারের সম্বন্ধে','সপরিবার = পরিবারসহ যে (বহুব্রীহি)']], exam:['“পিতামাতা”-র সমাস কী? ব্যাসবাক্য পিতা ও মাতা; তাই <b>ইতরেতর দ্বন্দ্ব</b>।','“রাজপুত্র” শব্দটি কোন সমাস? রাজার পুত্র—<b>সম্বন্ধ তৎপুরুষ</b>।','“নীলকমল” ও “নীলকণ্ঠ” একই নয়: নীল যে কমল = কর্মধারয়, নীল কণ্ঠ যার = বহুব্রীহি।','“যথাসাধ্য” শব্দে অব্যয়ীভাব: সাধ্য অনুযায়ী।','প্রশ্নে ব্যাসবাক্য দেওয়া থাকলে আগে তার সংযোগশব্দ (ও/কে/দিয়ে/থেকে/যার) ঘিরে নাও।'] };
const samasCompare = { id:'samas-compare', title:'যে জোড়ায় বেশি ভুল হয়: তুলনা', definition:'একই রকম দেখতে শব্দের সমাস নির্ণয়ে <b>ব্যাসবাক্য</b>ই শেষ কথা। শব্দের অর্থ না মিলিয়ে শুধু নাম দেখে সিদ্ধান্ত নেবে না।', table:{headers:['সমাস','ব্যাসবাক্যের সংকেত','উদাহরণ','কী মনে রাখবে'],rows:[['তৎপুরুষ','বিভক্তি: কে/দিয়ে/থেকে/র/এ','রাজপুত্র = রাজার পুত্র','পরপদ প্রধান'],['বহুব্রীহি','যার/যে; অন্য ব্যক্তি বা বস্তু বোঝায়','নীলকণ্ঠ = নীল কণ্ঠ যার','কোনও পদ সরাসরি প্রধান নয়'],['কর্মধারয়','বিশেষণ + বিশেষ্য; যে বসে','নীলকমল = নীল যে কমল','পরপদ প্রধান'],['বহুব্রীহি','যার বসে','পদ্মনয়ন = পদ্মের ন্যায় নয়ন যার','সমস্তপদে তৃতীয় অর্থ'],['দ্বন্দ্ব','ও/এবং বসে','সুখদুঃখ = সুখ ও দুঃখ','দুই পদের সমান গুরুত্ব']]}, tip:'“নীলকণ্ঠ” পাখির নাম হলে—নীল কণ্ঠ যার, বহুব্রীহি। “নীল কমল” হলে—নীল যে কমল, কর্মধারয়। প্রসঙ্গ বদলালে বিচারও বদলায়।', memory:'যার মানে বহুব্রীহি, যে মানে কর্মধারয়; কে-তে কর্ম তৎপুরুষ, ভুল আর হবে না হায়।', mistakes:[['সব “নীল+বিশেষ্য” কর্মধারয়','ব্যাসবাক্যে যার এলে বহুব্রীহি'],['শুধু শব্দ দেখে সমাস বলা','ব্যাসবাক্যের বিভক্তি দেখে বলা'],['দ্বিগু মানেই বহুব্রীহি','সংখ্যা-পূর্বপদ; ব্যাসবাক্য অনুযায়ী দ্বিগু বা বহুব্রীহি']], exam:['“দশানন” = দশ আনন যার—বহুব্রীহি।','“ত্রিফলা” = তিন ফলের সমাহার—দ্বিগু।','“গৃহবাস” = গৃহে বাস—অধিকরণ তৎপুরুষ।'] };

