const tenseSections = tenseDefinitions.map((def, index) => ({ id:def[0], title:def[1], definition:`<b>Formula:</b> ${def[2]}. এটি ${def[3].split(', ').join(', ')} বোঝাতে কাজে লাগে।`, support:'মনে রাখো: Formula-র helping verb-টি বদলালে tense-ও বদলে যায়। আগে helping verb ধরো, তারপর মূল verb দেখো।', formula:def[2], groups:[{title:'ব্যবহার ১ ও ২',rule:`এই tense মূলত ${def[3].split(', ').slice(0,2).join(' এবং ')} বোঝায়।`,examples:makeExamples(def[4].slice(0,4),8)},{title:'ব্যবহার ৩ ও ৪',rule:`আরও ব্যবহার: ${def[3].split(', ').slice(2).join(' এবং ')}।`,examples:makeExamples(def[4].slice(4),8)},{title:'Affirmative forms',rule:`বাক্যটি হ্যাঁ-বোধক হলে formula-টি সরাসরি বসাও।`,examples:makeExamples(def[4].slice(0,5),8)},{title:'Negative ও interrogative forms',rule:'Negative-এ not এবং প্রশ্নে auxiliary-কে subject-এর আগে বসাও।',examples:makeExamples(def[4].slice(3).concat(def[4].slice(0,2)),8)}], tip:`Signal words: ${index < 4 ? 'now, every day, already, since, for' : index < 8 ? 'yesterday, ago, when, before' : 'tomorrow, next, by, this time'}. সময়ের শব্দ দেখে tense মেলাও, কিন্তু শুধু শব্দ দেখে নয়—অর্থও দেখো।`, memory:`${def[1].split('/')[0]}: ${def[2]}`, mistakes:tenseErrorPairs[def[0]] || genericTenseErrors(def), exam:[`Choose the correct form: “She ___ her work already.” (has finished / finished / is finish / have finished). <b>Answer: has finished.</b>`,`Identify the tense: “They ${def[4][0].split(' ').slice(1).join(' ')}” — formula দেখে উত্তর দাও।`,`Fill in the blank with the formula <b>${def[2]}</b>.`]}));
const tenseOverview = {id:'tense-map',title:'১২টি Tense: 3 × 4 Master Map',definition:'Tense মানে কাজের সময়। তিনটি সময়—Present, Past, Future; প্রতিটিতে চারটি রূপ—Simple, Continuous, Perfect, Perfect Continuous।',table:{headers:['সময়','Simple','Continuous','Perfect','Perfect Continuous'],rows:[['Present','V1 / V1+s','am/is/are + V-ing','have/has + V3','have/has been + V-ing'],['Past','V2','was/were + V-ing','had + V3','had been + V-ing'],['Future','will + V1','will be + V-ing','will have + V3','will have been + V-ing']]},tip:'প্রথমে সময় ধরো, তারপর কাজটি সাধারণ/চলমান/শেষ/কতক্ষণ ধরে চলছে—এই চার প্রশ্ন করো।',memory:'সাধারণ কাজ Simple-এ, চলছে যখন Continuous-এ; শেষ হলে Perfect, কতক্ষণ হলে Perfect Continuous-এ।',mistakes:[['He has went.','He has gone.'],['I am knowing.','I know.'],['She did not went.','She did not go.'],['They will be goes.','They will go.'],['I have seen him yesterday.','I saw him yesterday.']],exam:['“since 2020” থাকলে সাধারণত perfect continuous দেখো।','“by next year” থাকলে future perfect-এর সম্ভাবনা বেশি।','দুটি অতীত কাজ হলে আগে ঘটে যাওয়া কাজে had + V3 বসে।']};
const tenseExtras = {id:'tense-extras',title:'Exam boosters: s/es, since/for ও verb forms',definition:'Tense-এর ছোট নিয়মগুলোতেই বেশি নম্বর কাটা যায়। এই অংশটি প্রতিদিন পাঁচ মিনিট দেখবে।',groups:[{title:'Simple Present: s / es / ies',rule:'He/She/It বা একবচন noun-এর পরে V1-এ s/es/ies যোগ হয়। consonant + y হলে y বাদ দিয়ে ies।',examples:['play → plays','watch → watches','go → goes','wash → washes','study → studies','try → tries','carry → carries','fix → fixes','teach → teaches','pass → passes','do → does','have → has','fly → flies','enjoy → enjoys','read → reads','work → works','push → pushes','catch → catches','cry → cries','obey → obeys']},{title:'Since vs For',rule:'Since = কখন থেকে (point of time); For = কতক্ষণ ধরে (period of time)।',examples:['since 2020','since Monday','since morning','since 5 o’clock','since childhood','for two hours','for a week','for three years','for a long time','for ten minutes','I have lived here since 2020.','I have lived here for six years.','She has waited since noon.','She has waited for two hours.','They have studied since dawn.']},{title:'Most useful irregular verbs',rule:'V1–V2–V3 মুখস্থ করলে tense, voice ও narration—তিন জায়গাতেই সুবিধা।',examples:['go – went – gone','come – came – come','see – saw – seen','write – wrote – written','eat – ate – eaten','do – did – done','give – gave – given','take – took – taken','speak – spoke – spoken','begin – began – begun','break – broke – broken','choose – chose – chosen','drink – drank – drunk','drive – drove – driven','fall – fell – fallen','forget – forgot – forgotten','know – knew – known','make – made – made','read – read – read','run – ran – run','sing – sang – sung','swim – swam – swum','teach – taught – taught','think – thought – thought','wear – wore – worn'] }],tip:'Present Perfect vs Simple Past: finished time (yesterday/last year) থাকলে Simple Past; সময় না বলে ফল বা অভিজ্ঞতা বোঝালে Present Perfect।',memory:'Since বলে শুরু বিন্দু, For বলে সময়ের দূর; V3 দেখলেই Perfect, ভুলটা যাবে দূর।',mistakes:[['I have gone there yesterday.','I went there yesterday.'],['She has been here since two hours.','She has been here for two hours.'],['He studies since morning.','He has been studying since morning.'],['Did you ever see the sea?','Have you ever seen the sea?'],['They have did it.','They have done it.'],['He go to school daily.','He goes to school daily.'],['She have finished.','She has finished.'],['I am having a car.','I have a car.'],['We had went.','We had gone.'],['He will has completed.','He will have completed.']],exam:['Fill in: “He ___ (study) since morning.” → <b>has been studying</b>.','Choose V3: “She has ___ a letter.” → <b>written</b>.','“By 2027, I ___ the course.” → <b>will have completed</b>.']};

