const articlesIntro = {id:'article-basics',title:'Article-এর মূল কথা: নতুন, চেনা, না-লাগা',definition:'Article হল noun-এর ছোট পরিচয়পত্র। <b>a/an</b> = একটি অনির্দিষ্ট বা নতুন জিনিস; <b>the</b> = নির্দিষ্ট/আগে চেনা জিনিস; <b>zero article</b> = কিছু noun-এর আগে কিছুই বসে না।',support:'মনে রাখো: a/an = একটা নতুন; the = সেই চেনা একটি। কিন্তু a/an বাছবে অক্ষর দেখে নয়, উচ্চারণের প্রথম sound দেখে।',groups:articleRuleData.map(([title,rule,examples]) => ({title,rule,examples})),tip:'প্রথমে noun-টির অর্থ বলো: “যে-কোনও একটি?”, “সেই নির্দিষ্টটি?”, নাকি “সাধারণভাবে?”—তিন প্রশ্নেই article ঠিক হবে।',memory:'নতুন হলে a/an ভাই, চেনা হলে the-ই পাই; সাধারণ নামের আগে অনেক সময় কিছুই নাই।',mistakes:articleMistakes.slice(0,10),exam:['Choose: “He is ___ honest man.” → <b>an</b>; কারণ honest-এর প্রথম sound vowel।','Choose: “___ Ganga is a holy river.” → <b>The</b>; নদীর আগে the।','Choose: “She goes to ___ school every day.” → <b>zero article</b>; শিক্ষার মূল উদ্দেশ্যে school।','Choose: “This is ___ best plan.” → <b>the</b>; superlative-এর আগে the।','Choose: “He is ___ university student.” → <b>a</b>; university-এর প্রথম sound /juː/।']};
