const bn1Method = { id:'bn1-method', title:'বাক্য থেকে পদ চেনার ৫ ধাপ', definition:'শব্দ আলাদা করে মুখস্থ না করে বাক্যের ভিতরে তার কাজ দেখলেই পদ নির্ণয় সহজ হয়।', groups:[{title:'Step-by-step method',rule:'প্রতিটি ধাপ একই বাক্যে প্রয়োগ করো: “পরিশ্রমী রিনা আজ মন দিয়ে পড়ে।”',examples:['ধাপ ১: নাম খোঁজো—রিনা; এটি বিশেষ্য।','ধাপ ২: নামের বদলি আছে কি? থাকলে সর্বনাম—সে পড়ে।','ধাপ ৩: নাম কেমন? পরিশ্রমী; এটি নাম-বিশেষণ।','ধাপ ৪: কাজ কী? পড়ে; এটি ক্রিয়া।','ধাপ ৫: কাজ কীভাবে/কখন? মন দিয়ে/আজ; এগুলি ক্রিয়া-বিশেষণ।']}],tip:'প্রশ্নের চাবি: কে/কী = বিশেষ্য বা সর্বনাম; কেমন/কত = বিশেষণ; কী করে = ক্রিয়া; কীভাবে/কখন/কোথায় = ক্রিয়া-বিশেষণ।',memory:'নাম বিশেষ্য, বদলি সর্বনাম; গুণ বিশেষণ, কাজ ক্রিয়ার প্রাণ।',mistakes:[['“ধীরে” বিশেষণ','“ধীরে” ক্রিয়া-বিশেষণ; হাঁটার রীতি বোঝায়'],['“ভালো ছেলে”-তে ভালো ক্রিয়া','ভালো নাম-বিশেষণ'],['“সে” বিশেষ্য','সে সর্বনাম'],['“আজ” বিশেষ্য','আজ কালবাচক ক্রিয়া-বিশেষণ'],['“আহা” সমুচ্চয়ী','আহা অনন্বয়ী অব্যয়'],['“এবং” অনুসর্গ','এবং সমুচ্চয়ী অব্যয়'],['“বই পড়ে”-তে পড়ে অকর্মক','বই কর্ম আছে, তাই সকর্মক'],['“হাসে” সকর্মক','কর্ম নেই, তাই অকর্মক'],['“মা শিশুকে দুধ দিলেন”-এ এক কর্ম','শিশুকে গৌণ, দুধ মুখ্য—দ্বিকর্মক'],['“নিজে” ব্যক্তিবাচক','নিজে আত্মবাচক সর্বনাম']],exam:['“পরিশ্রমী ছাত্র পড়ে”—পরিশ্রমী কোন পদ? <b>বিশেষণ</b>।','“সে দ্রুত দৌড়ায়”—দ্রুত কোন পদ? <b>ক্রিয়া-বিশেষণ</b>।','“মা শিশুকে দুধ দিলেন”—দিলেন কোন ক্রিয়া? <b>দ্বিকর্মক</b>।','“আহা, কী সুন্দর!”—আহা কোন অব্যয়? <b>অনন্বয়ী</b>।','“রবি ও সুমন এল”—ও কোন অব্যয়? <b>সমুচ্চয়ী</b>।'] };
