const bn5Compare = {id:'bn5-compare',title:'বাংলা ও তৎসম প্রত্যয়: তুলনা ও ট্রিক',definition:'বাংলা প্রত্যয় সাধারণ ব্যবহার ও কথ্য রূপে দেখা যায়; তৎসম প্রত্যয় সংস্কৃতধর্মী শব্দে বেশি। তবে পরীক্ষায় মুখস্থের সঙ্গে মূল শব্দটি শনাক্ত করাই নিরাপদ।',table:{headers:['ধরন','প্রত্যয়ের নমুনা','উদাহরণ','কী বোঝায়'],rows:[['কৃৎ','অক, য, তব্য, অন','লেখক, পাঠ্য, কর্তব্য, গমন','ধাতু থেকে নতুন শব্দ'],['তদ্ধিত','তা, ত্ব, ঈয়, ইক','সুন্দরতা, বন্ধুত্ব, ভারতীয়, মাসিক','নাম/বিশেষণ থেকে নতুন শব্দ'],['বাংলা রীতি','ওয়ালা, আলি, সুলভ','দুধওয়ালা, বাঙালি, শিশুসুলভ','প্রচলিত বাংলা ব্যবহার'],['তৎসম রীতি','অণ, ইক, ঈয়, তব্য','মানব, নাগরিক, ভারতীয়, কর্তব্য','সংস্কৃতঘেঁষা গঠন']]},groups:[{title:'প্রত্যয় নির্ণয়ের ৫ ধাপ',rule:'শেষাংশ কেটে বাকি অংশটির অর্থ আছে কি না পরীক্ষা করো; তারপর সেটি ধাতু না নামপ্রকৃতি নির্ণয় করো।',examples:['ধাপ ১: লেখক থেকে অক কাটো।','ধাপ ২: লেখ্ কাজ বোঝায়—ধাতু।','ধাপ ৩: তাই অক কৃৎ প্রত্যয়।','ধাপ ৪: বন্ধুত্ব থেকে ত্ব কাটো।','ধাপ ৫: বন্ধু নাম—তাই ত্ব তদ্ধিত প্রত্যয়।']}],tip:'শব্দের শেষের এক-দুই বর্ণ কেটে জোর করে প্রত্যয় বলবে না। কাটার পরে অর্থপূর্ণ প্রকৃতি থাকতে হবে।',memory:'অক-য-তব্য কৃৎ-এর দল, তা-ত্ব-ঈয় তদ্ধিত বল।',mistakes:[['“মানব”-এ মান প্রকৃতি','মনু প্রকৃতি; অণ প্রত্যয়'],['“গমন”-এ গম প্রত্যয়','গম্ প্রকৃতি; অন প্রত্যয়'],['“সাহসী”-তে সাহস প্রত্যয়','সাহস প্রকৃতি; ঈ প্রত্যয়'],['শেষাংশ কাটলেই প্রকৃতি ঠিক','কাটা অংশের পরে অর্থপূর্ণ মূল আছে কি না দেখো']],exam:['“নাগরিক” শব্দে প্রকৃতি কী? <b>নগর</b>।','“গমন”-এ প্রত্যয় কী? <b>অন</b>।','“মানবতা”-তে তদ্ধিত প্রত্যয় <b>তা</b>।']};
const en1NounTypes = [
 ['Proper nouns','A proper noun names one particular person, place, book, day or institution. It begins with a capital letter in English.',['Rabindranath wrote poems.','Kolkata is a busy city.','India is our country.','The Ganga is a holy river.','Monday is the first school day.','The Taj Mahal is beautiful.','Rina lives in Howrah.','Asia is the largest continent.','December is a cool month.','The Bible is a holy book.','Mount Everest is very high.','Provakar reads English daily.']],
 ['Common nouns','A common noun gives a general name to a person, place, animal or thing.',['The boy is smiling.','A teacher entered the room.','The river is wide.','A book is on the table.','The farmer works hard.','The doctor saw the patient.','A bird flew away.','The village is clean.','The girl has a pen.','The school opens at ten.','A child needs care.','The market is crowded.']],
 ['Collective nouns','A collective noun names a group as one unit.',['The team won the match.','A flock of birds flew south.','The jury gave its decision.','The class is quiet today.','A crowd gathered outside.','The committee meets on Monday.','A herd of cows is grazing.','The army protects the border.','A bunch of keys is missing.','The family is happy.','A pack of cards is on the table.','The audience clapped loudly.']],
 ['Abstract nouns','An abstract noun names a quality, feeling, state or idea that cannot be touched.',['Honesty is the best policy.','Kindness wins hearts.','Freedom is precious.','Childhood is memorable.','Beauty attracts everyone.','Wisdom comes with experience.','Happiness is not costly.','Bravery helps in danger.','Truth always wins.','Poverty causes suffering.','Knowledge gives power.','Friendship needs trust.']],
 ['Material nouns','A material noun names a substance or material.',['Water is essential for life.','Gold is a precious metal.','Milk is good for health.','Cotton is soft.','Iron is used for bridges.','Wood makes furniture.','Rice is our staple food.','Oil is used in cooking.','Glass can break easily.','Sand is used in construction.','Sugar tastes sweet.','Wool keeps us warm.']]
];
const en1NounSection = {id:'en1-noun',title:'Noun: the naming word',definition:'A <b>noun</b> is the name of a person, place, animal, thing, quality or idea. যার নাম আছে সেটাই Noun!',support:'মনে রাখো: নাম বলতে শুধু রিনা বা কলকাতা নয়—সততা, জল, দল—সবই noun হতে পারে।',groups:en1NounTypes.map(([title,rule,examples])=>({title,rule,examples})).concat([{title:'Singular → Plural: 20 exam patterns',rule:'Most nouns take -s; words ending in s, sh, ch, x, o often take -es; consonant + y changes to -ies. Learn the irregular forms separately.',examples:['book → books','pen → pens','class → classes','bus → buses','watch → watches','box → boxes','hero → heroes','potato → potatoes','baby → babies','city → cities','leaf → leaves','wife → wives','man → men','woman → women','child → children','tooth → teeth','foot → feet','mouse → mice','sheep → sheep','deer → deer']},{title:'Countable and uncountable nouns',rule:'Countable nouns can be counted; uncountable nouns are measured, not counted one by one.',examples:['Countable: one apple, two apples.','Countable: a chair, many chairs.','Countable: a book, several books.','Countable: a student, few students.','Countable: a coin, many coins.','Countable: an egg, six eggs.','Countable: a bottle, three bottles.','Countable: a village, many villages.','Uncountable: some water, not waters.','Uncountable: much information, not informations.','Uncountable: a piece of advice, not an advice.','Uncountable: some furniture, not furnitures.','Uncountable: a little rice, not rices.','Uncountable: much milk, not milks.','Uncountable: some news, not newses.']},{title:'Gender: useful pairs',rule:'Masculine denotes male, feminine denotes female; common gender may be either, and neuter is inanimate.',examples:['king → queen','actor → actress','hero → heroine','nephew → niece','uncle → aunt','brother → sister','husband → wife','son → daughter','father → mother','gander → goose','drake → duck','horse → mare','bull → cow','monk → nun','widower → widow','teacher → teacher (common)','child → child (common)','friend → friend (common)','book → book (neuter)','river → river (neuter)']}]),tip:'Shortcut: if you can put “a/an” before a word and count it, it is often countable. Information, advice, furniture and news are common exam traps.',memory:'Name a person, place or thing; quality, idea—noun will ring.',mistakes:[['He gave me an advice.','He gave me a piece of advice.'],['She has many informations.','She has much information.'],['The furnitures are new.','The furniture is new.'],['I bought two breads.','I bought two loaves of bread.'],['Childs are playing.','Children are playing.'],['Sheeps are grazing.','Sheep are grazing.'],['The news are good.','The news is good.'],['He has a good knowledges.','He has good knowledge.'],['The sceneries are beautiful.','The scenery is beautiful.'],['My luggages are heavy.','My luggage is heavy.']],exam:['Choose the correct form: “The ___ is good.” (news / newses) → <b>news</b>.','Choose the plural: “child” → <b>children</b>.','Find the abstract noun: “Honesty is a virtue.” → <b>Honesty</b>.','Choose the material noun: gold / teacher / team / bravery → <b>gold</b>.']};
const personalChart = [['First singular','I','me','my','mine','myself'],['Second singular/plural','you','you','your','yours','yourself/yourselves'],['Third masculine','he','him','his','his','himself'],['Third feminine','she','her','her','hers','herself'],['Third neuter','it','it','its','—','itself'],['First plural','we','us','our','ours','ourselves'],['Third plural','they','them','their','theirs','themselves']];
const en1PronounSection = {id:'en1-pronoun',title:'Pronoun: a noun’s helpful substitute',definition:'A <b>pronoun</b> replaces a noun, so we do not repeat the same name again and again.',support:'মনে রাখো: Rina is kind. Rina helps me. দ্বিতীয় Rina-এর বদলে <i>She</i> বসালে সেটি pronoun।',table:{headers:['Person','Subject','Object','Possessive adjective','Possessive pronoun','Reflexive'],rows:personalChart},groups:[{title:'Personal pronouns',rule:'Use subject forms before a verb and object forms after a verb or preposition.',examples:['I read every day.','She sings well.','They play football.','The teacher called me.','Please help him.','Rina saw us.','This is my pen.','That bag is hers.','Our village is clean.','The victory is theirs.']},{title:'Reflexive and emphatic pronouns',rule:'Reflexive pronouns refer back to the subject; emphatic pronouns add stress.',examples:['I hurt myself.','She taught herself.','They enjoyed themselves.','We prepared ourselves.','He blamed himself.','I myself checked the answer.','The principal himself spoke.','She herself wrote the letter.','We ourselves cleaned the room.','They themselves solved it.']},{title:'Demonstrative pronouns',rule:'This/these point to what is near; that/those point to what is farther away.',examples:['This is my book.','That is your chair.','These are fresh flowers.','Those are old trees.','This is easy.','That was a good idea.','These belong to me.','Those look expensive.','This pen writes well.','Those students are ready.']},{title:'Indefinite pronouns',rule:'Indefinite pronouns refer to people or things without naming them exactly.',examples:['Someone is at the door.','Everyone is ready.','Nobody knows the answer.','Anything can happen.','Nothing is impossible.','Each has a pen.','Many were absent.','Few understand the rule.','One should be honest.','Anybody can apply.']},{title:'Relative pronouns',rule:'Who is for people, which for things, that for people/things; whose shows possession.',examples:['The boy who won is my friend.','The book which I bought is useful.','The girl whose pen is lost is crying.','This is the house that I like.','The man whom I met was polite.','I know the teacher who helped you.','The car which stopped is new.','The child that smiled is happy.','The student whose answer is correct won.','This is what I wanted.']},{title:'Interrogative pronouns',rule:'Who, whom, whose, which and what ask questions.',examples:['Who is there?','Whom did you meet?','Whose book is this?','Which do you prefer?','What happened?','Who called me?','What is your name?','Which is correct?','Whom should I ask?','Whose are these shoes?']},{title:'Reciprocal pronouns',rule:'Each other is usually for two; one another is usually for more than two.',examples:['The two friends help each other.','The sisters love each other.','The players congratulated one another.','We should respect one another.','The twins look at each other.','The teams greeted each other.','Students teach one another.','The brothers support each other.','Neighbours help one another.','The partners trusted each other.']},{title:'Subject vs object: 10 pairs',rule:'After a verb or preposition, use me/him/her/us/them—not I/he/she/we/they.',examples:['She and I went there.','The teacher called Rina and me.','He gave the book to her and me.','My brother and I study together.','Between you and me, it is difficult.','They invited him and her.','You and he are ready.','Please tell us the answer.','The prize was for Rina and me.','She helped them yesterday.']}],tip:'Remove the other person’s name to check: “The teacher called Rina and me” → “The teacher called me,” not “called I.”',memory:'Before verb I/he/she/we/they; after verb me/him/her/us/them apply.',mistakes:[['Me and Rina went.','Rina and I went.'],['The teacher called Rina and I.','The teacher called Rina and me.'],['Between you and I.','Between you and me.'],['Each students have a pen.','Each student has a pen.'],['Everyone have finished.','Everyone has finished.'],['Myself am Rina.','I am Rina.'],['This is her book; it is her.','This is her book; it is hers.'],['Who did you meet? (formal object)','Whom did you meet?'],['The boy which came.','The boy who came.'],['One should do their duty.','One should do one’s duty.']],exam:['Choose: “The teacher praised Rina and ___.” → <b>me</b>.','Choose: “Everyone ___ ready.” → <b>is</b>.','Fill in: “This is the boy ___ won.” → <b>who</b>.','Choose: “The two sisters help ___.” → <b>each other</b>.']};
const en1AdjectiveSection = {id:'en1-adjective',title:'Adjective: the describing word',definition:'An <b>adjective</b> describes a noun or pronoun: its quality, number, quantity, position or ownership.',support:'মনে রাখো: “a <i>red</i> flower”—red বলছে flower কেমন; তাই এটি adjective।',groups:[{title:'Types of adjective',rule:'Descriptive tells quality; numeral tells number/order; quantitative tells amount; demonstrative points out; interrogative asks; possessive shows ownership; proper comes from a proper noun.',examples:['a beautiful flower (descriptive)','three pens (numeral)','little water (quantitative)','this book (demonstrative)','which road? (interrogative)','my school (possessive)','Indian food (proper)','a brave soldier (descriptive)','the first prize (numeral)','much milk (quantitative)','those houses (demonstrative)','what colour? (interrogative)','her dress (possessive)','Bengali literature (proper)']},{title:'Degrees: regular and irregular forms',rule:'Positive compares no degree, comparative compares two, superlative compares more than two. Short adjectives often take -er/-est; longer ones take more/most.',examples:['tall → taller → tallest','small → smaller → smallest','happy → happier → happiest','easy → easier → easiest','big → bigger → biggest','hot → hotter → hottest','beautiful → more beautiful → most beautiful','careful → more careful → most careful','useful → more useful → most useful','good → better → best','bad → worse → worst','little → less → least','much/many → more → most','far → farther/further → farthest/furthest','old → older/elder → oldest/eldest','late → later → latest','wise → wiser → wisest','brave → braver → bravest','busy → busier → busiest','important → more important → most important']},{title:'OSASCOMP adjective order',rule:'Opinion, Size, Age, Shape, Colour, Origin, Material, Purpose, Noun. Do not pile adjectives randomly.',examples:['a beautiful small old red Italian wooden table','a lovely large new round blue plastic box','an expensive little black leather bag','a nice big old Bengali house','a beautiful long white cotton dress','a small square metal tin','an ugly old brown wooden chair','a smart young Indian student','a large modern glass building','a lovely red silk scarf']}],tip:'Two things → comparative + than. Three or more → the + superlative. Never write “more better” or “most tallest.”',memory:'O-S-A-S-C-O-M-P: Opinion, Size, Age, Shape, Colour, Origin, Material, Purpose.',mistakes:[['This is more better.','This is better.'],['He is tallest than me.','He is taller than me.'],['She is the most tallest girl.','She is the tallest girl.'],['I have a red beautiful flower.','I have a beautiful red flower.'],['She is elder than me.','She is older than me.'],['Much students came.','Many students came.'],['A few water is left.','A little water is left.'],['He is junior than me.','He is junior to me.'],['This book is preferable than that.','This book is preferable to that.'],['He is more cleverer.','He is cleverer.']],exam:['Choose: “Rina is ___ than Mina.” → <b>taller</b>.','Choose: “This is the ___ road.” → <b>shortest</b>.','Correct order: a beautiful red silk sari.','Choose quantity: ___ water → <b>little/a little</b>.']};
