const en1VerbSection = {id:'en1-verb',title:'Verb: the action or state word',definition:'A <b>verb</b> tells what someone does, is, has or feels. Without a finite verb, a full English clause cannot stand.',support:'মনে রাখো: কাজ (run), অবস্থা (is), থাকা (have)—সবই verb-এর কাজ।',groups:[{title:'Types of verb',rule:'Main verbs carry meaning; auxiliaries help them. Transitive verbs take objects; intransitive do not; linking verbs connect the subject with a description.',examples:['She writes a letter. (main)','He is reading. (auxiliary + main)','They have finished. (auxiliary + main)','Rina reads a book. (transitive)','The baby sleeps. (intransitive)','The soup tastes good. (linking)','She became happy. (linking)','We made a plan. (transitive)','Birds fly. (intransitive)','I do my work. (main)','They are ready. (linking)','He has a bicycle. (main)']},{title:'Finite and non-finite verbs',rule:'A finite verb changes with tense/subject. Non-finite forms do not: infinitive (to + V1), gerund (V-ing as noun), participle (V-ing/V3 as adjective).',examples:['She writes daily. (finite)','They wrote yesterday. (finite)','He goes to school. (finite)','I want to learn. (infinitive)','To err is human. (infinitive)','She likes to sing. (infinitive)','Swimming is good exercise. (gerund)','Reading improves knowledge. (gerund)','He enjoys playing. (gerund)','The crying baby slept. (present participle)','A broken glass lay there. (past participle)','The smiling girl waved. (present participle)']},{title:'12 modal auxiliaries',rule:'Modals are followed by V1. They express ability, possibility, permission, duty, advice or habit.',examples:['can: I can swim.','could: Could you help me?','may: May I come in?','might: It might rain.','will: I will return.','would: Would you like tea?','shall: Shall we start?','should: You should revise.','must: We must obey rules.','ought to: You ought to help.','need: You need not worry.','dare: Dare he speak?','used to: I used to play here.','can: She can solve it.','may: The teacher may come.','should: You should not waste time.','must: You must wear a helmet.','would: I would rather stay.','could: He could read at five.','used to: They used to live here.']},{title:'Subject–verb agreement: 15 rules',rule:'A singular subject takes a singular verb; a plural subject takes a plural verb. Find the real subject, not the nearest noun.',examples:['He plays well.','They play well.','Each student has a card.','Every boy is ready.','Either Rina or Mina is coming.','Neither the boys nor the teacher is late.','Neither the teacher nor the boys are late.','The news is true.','Mathematics is difficult.','The police are alert.','A pair of shoes is new.','Ten kilometres is a long distance.','Bread and butter is my breakfast.','The quality of the mangoes is good.','One of the boys is absent.']},{title:'50 useful irregular verbs',rule:'V1–V2–V3 are tested in tense, voice and narration. Read the three forms aloud every day.',examples:en1VerbForms}],tip:'After do/does/did and every modal, always use V1: “did go”, “can write”, never “did went” or “can writes.”',memory:'Modal-এর পরে V1 বসে; did-এর পরেও V1 হাসে.',mistakes:[['He do not know.','He does not know.'],['She can sings.','She can sing.'],['Did you went?','Did you go?'],['I am agree.','I agree.'],['He is having a car.','He has a car.'],['She enjoy to sing.','She enjoys singing.'],['I look forward to meet you.','I look forward to meeting you.'],['The baby is slept.','The baby is sleeping.'],['He has wrote.','He has written.'],['One of the boys are absent.','One of the boys is absent.']],exam:['Choose: “Each of the boys ___ a pen.” → <b>has</b>.','Choose V3: write → <b>written</b>.','Choose: “She can ___.” → <b>sing</b>.','Identify non-finite: “Swimming is good.” → <b>Swimming</b>.']};
const en1AdverbSection = {id:'en1-adverb',title:'Adverb: how, when, where and how much',definition:'An <b>adverb</b> modifies a verb, adjective or another adverb. It tells manner, time, place, frequency, degree or affirmation.',support:'মনে রাখো: adjective noun-কে সাজায়; adverb সাধারণত verb/adjective/adverb-কে সাজায়—“She sings beautifully.”',groups:[{title:'Adverb of manner',rule:'It tells how an action happens.',examples:['She sings beautifully.','He runs quickly.','Please speak slowly.','The baby slept peacefully.','Rina answered correctly.','The driver drove carefully.','They worked hard.','The child smiled happily.','Write neatly.','He spoke politely.']},{title:'Adverb of time',rule:'It tells when an action happens.',examples:['I will come tomorrow.','She arrived early.','We met yesterday.','He has just left.','They will return soon.','I have already eaten.','Wait here now.','The train came late.','We often study at night.','She will call later.']},{title:'Adverb of place',rule:'It tells where an action happens.',examples:['Come here.','Go there.','The children are outside.','He looked everywhere.','The bird flew away.','Please sit downstairs.','She lives nearby.','The dog is inside.','Look up.','The train went abroad.']},{title:'Adverb of frequency',rule:'It tells how often an action happens.',examples:['I always revise.','She usually walks.','They often visit us.','He sometimes forgets.','We rarely argue.','She never lies.','I generally wake early.','They frequently practise.','He occasionally calls.','We hardly complain.']},{title:'Adverb of degree',rule:'It tells how much or to what extent.',examples:['It is very cold.','She is quite ready.','He is too tired.','The water is almost hot.','I am completely sure.','This is rather difficult.','The bag is extremely heavy.','She is nearly there.','It is enough.','The room is fairly large.']},{title:'Adverb of affirmation/negation',rule:'It confirms or denies an idea.',examples:['She certainly knows.','He definitely agreed.','Perhaps it will rain.','Surely you can try.','Indeed, it is true.','Yes, I understand.','No, I will not go.','Certainly, we will help.','Obviously, the answer is correct.','Maybe they are late.']},{title:'Adjective vs adverb: common pairs',rule:'After linking verbs use adjectives; to describe an action use adverbs.',examples:['She is a careful driver.','She drives carefully.','The soup tastes good.','He played well.','I feel bad today.','The baby slept soundly.','This is a fast train.','The train runs fast.','He is hard-working.','He works hard.']},{title:'Position rules',rule:'Frequency adverbs usually come before the main verb but after be; manner usually comes after the object.',examples:['She always comes early.','He is always polite.','They have never visited us.','I often read at night.','We do not usually eat late.','She speaks English well.','He completed the task carefully.','Tomorrow I will call you.','I will call you tomorrow.','Perhaps he is right.']}],tip:'Ask “how?”—usually manner adverb; “what kind?”—adjective. After feel, look, seem, taste, smell, sound, become use an adjective.',memory:'Verb-এর কাজ কীভাবে হয়? adverb উত্তর রয়; noun কেমন হলে adjective সয়।',mistakes:[['She sings beautiful.','She sings beautifully.'],['He is feeling badly.','He is feeling bad.'],['The flower smells sweetly.','The flower smells sweet.'],['He works hardly.','He works hard.'],['I am very happily.','I am very happy.'],['She is a beautifully girl.','She is a beautiful girl.'],['He drives careless.','He drives carelessly.'],['The soup tastes deliciously.','The soup tastes delicious.'],['I never have seen it.','I have never seen it.'],['She speaks fluent English.','She speaks English fluently.']],exam:['Choose: “She sings ___.” → <b>beautifully</b>.','Choose: “The soup tastes ___.” → <b>good</b>.','Place adverb: “He is ___ late.” → <b>always</b>.']};
