const bn7Main = {id:'bn7-transform',title:'বাক্য পরিবর্তন: সরল, জটিল ও যৌগিক',definition:'একটি ভাবকে ভিন্ন বাক্যগঠনে প্রকাশ করাই বাক্য পরিবর্তন। সরলে একটি সমাপিকা ক্রিয়া, জটিলে প্রধান-অপ্রধান উপবাক্য, যৌগিকে সমমানের একাধিক বাক্য থাকে।',groups:[{title:'চেনার ট্রিক',rule:'সরল: এক প্রধান সমাপিকা ক্রিয়া। জটিল: যে/যদি/যখন/যেহেতু-জাত উপবাক্য। যৌগিক: এবং/কিন্তু/তাই/অথবা দিয়ে সমমানের বাক্য।',examples:['সরল: বৃষ্টির জন্য খেলা বন্ধ হল।','জটিল: যেহেতু বৃষ্টি হল, সেহেতু খেলা বন্ধ হল।','যৌগিক: বৃষ্টি হল, তাই খেলা বন্ধ হল.']},...bn7Transforms.map(([title,rule,examples])=>({title,rule,examples})),...bn7VoiceGroups],tip:'রূপান্তরে ভাব বদলানো চলবে না। আগে মূল ভাবটি বলো, তারপর সংযোগশব্দ বা পদবন্ধ বদলাও।',memory:'এক ক্রিয়ায় সরল সাজে, উপবাক্যে জটিল বাজে; সমান বাক্য জোড়া হলে যৌগিক সে কাজে।',mistakes:bn7CorrectionPairs.slice(0,10),exam:['“যে ছেলে পরিশ্রমী, সে সফল”—কোন বাক্য? <b>জটিল</b>.','সরল করো: “বৃষ্টি হল, তাই খেলা বন্ধ হল।” → <b>বৃষ্টির জন্য খেলা বন্ধ হল</b>.','কর্তৃবাচ্য করো: “তার দ্বারা কাজটি করা হয়।” → <b>সে কাজটি করে</b>.','“এখানে ধূমপান করা নিষেধ”—কোন বাচ্য? <b>ভাববাচ্য</b>.','যৌগিক করো: “পরিশ্রম করে সে জিতল।” → <b>সে পরিশ্রম করল এবং জিতল</b>.']};
