const bn8Main = {id:'bn8-literature-data',title:'সাহিত্য: নাম, গ্রন্থ, চরিত্র ও প্রথম তথ্য',definition:'সাহিত্য প্রশ্নে তথ্য মুখস্থের সঙ্গে যুগ, রচয়িতা ও চরিত্রকে জোড়া লাগাও। একই লেখকের দুই-তিনটি গ্রন্থ একসঙ্গে পড়লে ভুল কম হয়।',table:{headers:['★','লেখক','ছদ্মনাম / পরিচিত নাম'],rows:makeVocabRows(bnPenNameSeed,50,20)},filterable:true,filterLabel:'লেখক বা ছদ্মনাম খুঁজুন',groups:[{title:'বাংলা সাহিত্যের যুগ: timeline',rule:'প্রাচীন (চর্যাপদ; বৌদ্ধ সহজিয়া ভাব), মধ্য (মঙ্গলকাব্য, বৈষ্ণব পদাবলি, অনুবাদ সাহিত্য), আধুনিক (গদ্য, উপন্যাস, নাটক, ছোটগল্প, নবজাগরণ)।',examples:['প্রাচীন যুগ: আনুমানিক ১০ম–১২শ শতক; প্রধান নিদর্শন চর্যাপদ।','মধ্যযুগ: আনুমানিক ১৩শ–১৮শ শতক; মঙ্গলকাব্য ও বৈষ্ণব সাহিত্য প্রধান।','আধুনিক যুগ: উনিশ শতক থেকে; গদ্য, উপন্যাস, নাটক ও সংবাদপত্রের বিকাশ।','প্রাচীন যুগের নাম: লুইপা, কাহ্নপা, শবরপা।','মধ্যযুগের নাম: চণ্ডীদাস, কৃত্তিবাস, মুকুন্দরাম।','আধুনিক যুগের নাম: বঙ্কিমচন্দ্র, রবীন্দ্রনাথ, নজরুল, শরৎচন্দ্র.']}],tip:'একজন লেখক → একটি বিখ্যাত গ্রন্থ → একটি চরিত্র—এই তিনটি কার্ড করে পড়ো। যেমন: শরৎচন্দ্র → দেবদাস → পার্বতী।',memory:'চর্যাপদ প্রাচীন চিহ্ন, মঙ্গল-মধ্যের সঙ্গী; আধুনিকে গদ্য-উপন্যাসে বাংলা হলো রঙ্গী।',mistakes:[['দুর্গেশনন্দিনী রবীন্দ্রনাথের','দুর্গেশনন্দিনী বঙ্কিমচন্দ্রের'],['পথের পাঁচালী শরৎচন্দ্রের','পথের পাঁচালী বিভূতিভূষণের'],['ফেলুদা শরদিন্দুর','ফেলুদা সত্যজিৎ রায়ের'],['ব্যোমকেশ সত্যজিৎ রায়ের','ব্যোমকেশ শরদিন্দু বন্দ্যোপাধ্যায়ের'],['চর্যাপদ আধুনিক যুগের','চর্যাপদ প্রাচীন যুগের']],exam:['“ভানুসিংহ” কার ছদ্মনাম? <b>রবীন্দ্রনাথ ঠাকুর</b>.','“বনফুল” কার ছদ্মনাম? <b>বলাইচাঁদ মুখোপাধ্যায়</b>.','“পরশুরাম” কার ছদ্মনাম? <b>রাজশেখর বসু</b>.']};
