const bn9Main = {id:'bn9-technique',title:'Unseen Passage: Smart 5-Step Technique',definition:'বোধপরীক্ষণে ভালো নম্বরের চাবি হল দ্রুত পড়া নয়, উদ্দেশ্য নিয়ে পড়া। প্রশ্নের উত্তর passage-এর ভেতরেই থাকে।',groups:[{title:'পাঁচ ধাপ',rule:'সময় ভাগ করো: প্রথম পাঠ ২ মিনিট, প্রশ্ন ১ মিনিট, প্রমাণ খোঁজা ৪ মিনিট, উত্তর ২ মিনিট, review ১ মিনিট।',examples:['ধাপ ১: শিরোনাম ও প্রথম বাক্য পড়ে বিষয় ধরো।','ধাপ ২: মূল শব্দে চোখ রাখো—কারণ, ফল, ব্যক্তি, সময়।','ধাপ ৩: প্রশ্ন পড়ে passage-এ প্রমাণের লাইন খোঁজো।','ধাপ ৪: MCQ-তে সব বিকল্পের সঙ্গে প্রমাণ মেলাও।','ধাপ ৫: শেষে উত্তরগুলি passage-বিরোধী কি না যাচাই করো.']},{title:'পাঁচ ধরনের প্রশ্নের কৌশল',rule:'মূল ভাব, তথ্য, শব্দার্থ, কারণ-ফল, অনুমান—প্রতিটির জন্য আলাদা দৃষ্টি দরকার।',examples:['মূল ভাব: প্রথম ও শেষ বাক্য মিলিয়ে দেখো।','তথ্য: সরাসরি একই শব্দ বা তথ্য খোঁজো।','শব্দার্থ: আশপাশের বাক্য থেকে অর্থ অনুমান করো।','কারণ-ফল: কারণের পরে কী ঘটেছে খুঁজে নাও।','অনুমান: passage-এর তথ্যের বাইরে যেও না।']}],tip:'কঠিন শব্দে আটকে পুরো passage থামিও না। আগে বাক্যের সামগ্রিক অর্থ ধরো, তারপর প্রয়োজনে শব্দে ফিরো।',memory:'বিষয় ধরো, প্রশ্ন পড়ো; প্রমাণ খুঁজে উত্তর গড়ো।',mistakes:[['প্রথম পছন্দের বিকল্পেই টিক','চারটি বিকল্প passage-এর সঙ্গে মিলিয়ে দেখা'],['নিজের জ্ঞান জুড়ে দেওয়া','লেখার প্রমাণে থাকা'],['শব্দার্থ না জেনে ফাঁকা রাখা','প্রসঙ্গ থেকে সম্ভাব্য অর্থ নেওয়া']],exam:['প্রশ্নের keyword passage-এ খোঁজার অভ্যাস করো।','সময় শেষের এক মিনিট শুধু ভুল টিক আছে কি না দেখো।']};
