const en7Main = {id:'en7-errors',title:'Sentence Correction: 15 error types',definition:'Error spotting is not guesswork. Read the sentence in layers: subject–verb, tense, article, preposition, pronoun, word form and unnecessary words.',support:'মনে রাখো: ৩০ সেকেন্ডে আগে verb ও subject ধরো, তারপর article/preposition, শেষে ছোট শব্দ—tag, pronoun, apostrophe।',groups:en7ErrorTypes.map(([title,rule,examples])=>({title,rule,examples})),tip:'30-second technique: (1) underline subject (2) circle verb (3) look for time word (4) scan article/preposition (5) read once aloud for redundancy.',memory:'Subject-verb আগে ধরো, tense তারপর মিল; article-preposition শেষে, error spotting skill।',mistakes:[['He do not know.','He does not know.'],['She did not went.','She did not go.'],['I need an advice.','I need a piece of advice.'],['She is good in maths.','She is good at maths.'],['Me and Rina went.','Rina and I went.'],['He is more better.','He is better.'],['Its raining.','It’s raining.'],['Return back.','Return.'],['I do not know nothing.','I do not know anything.'],['He enjoys to sing.','He enjoys singing.']],exam:['Spot the error: “Each students have a pen.” → <b>Each student has a pen.</b>','Spot the error: “He has wrote.” → <b>He has written.</b>','Spot the error: “The news are good.” → <b>The news is good.</b>.']};
const en7Transform = {id:'en7-transform',title:'Sentence Transformation and Fill in the Blanks',definition:'Transformation changes the form, not the meaning. First understand the original sentence, then choose the right pattern.',support:'মনে রাখো: form বদলাবে, meaning বদলাবে না। বদলানোর পরে নিজের কাছে বাংলায় অর্থ মিলিয়ে দেখো।',groups:en7TransformGroups.concat([{title:'100 Mixed Fill-in-the-Blanks',rule:'Hint: find the word class and grammar clue before choosing.',examples:makeExamples(en7FillBlanks,100)}]),tip:'একটি transformation শেষ করে মূল বাক্য ও নতুন বাক্যের অর্থ একবার মিলিয়ে নাও। এক শব্দের ভুলে পুরো ভাব বদলে যেতে পারে।',memory:'Meaning same, structure new; transformation practice makes grammar true.',mistakes:[['No other boy is taller than Rina.','No other boy is as tall as Rina.'],['He is too weak that he cannot walk.','He is too weak to walk.'],['She is so clever girl that…','She is such a clever girl that…']],exam:['Negative করো: “He is always punctual.” → <b>He is never late.</b>','Complex করো: “On seeing the police, he ran.” → <b>When he saw the police, he ran.</b>','Fill: “She is interested ___ music.” → <b>in</b>.']};
const enPassages = [
 {id:'en8-panchayat',title:'Passage 1: Panchayati Raj',text:'Panchayati Raj brings government closer to rural people. Instead of waiting for decisions from distant offices, villagers can discuss local needs through elected representatives and Gram Sabha meetings. Clean drinking water, village roads, drainage, primary schools, health centres and work opportunities are common concerns. A good Panchayat does not merely spend money; it listens to people, prepares a clear plan, keeps records open and checks the quality of completed work. Participation matters greatly. Women, elderly people, farmers, workers and persons with disabilities may experience a village differently, so their voices improve a plan. Citizens also have duties: they should attend meetings, protect public property, avoid spreading false information and ask respectful questions. When people and representatives work together honestly, small improvements become lasting development. Panchayati Raj therefore teaches an important democratic lesson: development is strongest when it is planned with people, not only for people.',questions:[['What is the main purpose of Panchayati Raj?','To bring government closer to rural people','To close village schools','To increase distant offices','To stop meetings','To bring government closer to rural people'],['Which is mentioned as a local concern?','Clean drinking water','Space travel','Foreign trade','Cinema tickets','Clean drinking water'],['What does a good Panchayat do besides spending money?','Keeps records open and checks work','Avoids all meetings','Ignores people','Only collects taxes','Keeps records open and checks work'],['Why should different groups participate?','They experience village needs differently','They all have the same problem','To cancel plans','To avoid democracy','They experience village needs differently'],['The passage says development is strongest when it is planned:','with people','against people','only in cities','by distant offices alone','with people']]},
 {id:'en8-environment',title:'Passage 2: Environment',text:'The environment is not an extra part of life; it is the system that supports life itself. Air, water, soil, plants and animals are connected in ways that people do not always notice. When a pond is polluted, fish suffer first, but people who depend on that water may also suffer later. When trees are cut without planning, the soil can lose moisture and birds can lose shelter. Climate change makes this connection even clearer. Unusual heat, irregular rainfall and stronger storms affect crops, health and daily work. The solution is not only a large government project. Small habits matter too: saving water, carrying a reusable bag, separating waste, planting local trees and switching off unused lights. Schools can encourage students to observe their surroundings and take part in cleaning drives. Real environmental care does not mean refusing all development. It means choosing development that uses resources wisely and leaves a safe, healthy world for the next generation.',questions:[['What supports life according to the passage?','The environment','Only machines','Only money','Only cities','The environment'],['What may happen when trees are cut without planning?','Soil loses moisture','Rivers become books','Days become shorter','Schools close','Soil loses moisture'],['Which is a small helpful habit?','Separating waste','Wasting water','Burning plastic','Leaving lights on','Separating waste'],['What does environmental care mean?','Wise use of resources','Stopping every development','Ignoring pollution','Using more waste','Wise use of resources'],['Who should receive a safe world?','The next generation','Only tourists','Only officials','Nobody','The next generation']]},
 {id:'en8-freedom',title:'Passage 3: Freedom Movement',text:'India’s freedom movement was a long struggle in which people from many regions, languages and communities joined a common cause. The movement did not depend on one method alone. Some leaders organised public meetings, petitions and boycotts; others inspired people through writing, education and social reform. The Swadeshi movement encouraged the use of Indian goods and gave new confidence to local industries. Mahatma Gandhi’s ideas of truth and non-violence brought ordinary people into national politics. Non-cooperation, civil disobedience and the Quit India movement showed that a united public could challenge unjust rule. Many young revolutionaries also accepted great personal risk for freedom. Women, students, farmers and workers all played important roles. Independence in 1947 was therefore not simply a change of rulers. It represented a hope for dignity, equality and the right to shape a country’s future. The movement still reminds us that democracy needs courage, unity and respect for different voices.',questions:[['What united people in the freedom movement?','A common cause','One language only','One city only','A sports team','A common cause'],['What did Swadeshi encourage?','Use of Indian goods','Use of no goods','Only foreign goods','Closing industries','Use of Indian goods'],['Whose ideas brought ordinary people into national politics?','Mahatma Gandhi’s','A foreign ruler’s','Only writers’','Only students’','Mahatma Gandhi’s'],['India became independent in:','1947','1905','1919','1950','1947'],['The movement reminds us democracy needs:','Courage, unity and respect','Silence and fear','Only wealth','No participation','Courage, unity and respect']]},
 {id:'en8-rural-tech',title:'Passage 4: Rural Technology',text:'Technology can improve rural life when it is simple, affordable and suited to local needs. A solar lamp, for example, can help a student study after sunset in a village with an uncertain electricity supply. A mobile phone can give farmers weather information and market prices. Small machines can reduce hard physical work, while digital records can make public services more transparent. However, technology alone cannot solve every problem. People need training to use a device safely and confidently. Repair facilities, local language instructions and reliable networks are also necessary. If a machine is too costly or cannot be repaired nearby, it may remain unused. The best rural technology is therefore not always the newest technology. It is the technology that local people can understand, maintain and adapt. When communities take part in choosing tools, technology becomes a partner in development rather than an object imposed from outside.',questions:[['What can a solar lamp help a student do?','Study after sunset','Travel abroad','Grow taller','Avoid reading','Study after sunset'],['What information can phones give farmers?','Weather and market prices','Only movie news','No useful information','Exam marks only','Weather and market prices'],['What is needed besides technology?','Training and repair facilities','Only advertisements','Less understanding','No local language','Training and repair facilities'],['The best technology is always:','Suitable and maintainable, not merely newest','The most costly','The largest','From outside only','Suitable and maintainable, not merely newest'],['Communities should do what?','Take part in choosing tools','Ignore all tools','Avoid learning','Only wait','Take part in choosing tools']]},
 {id:'en8-women',title:'Passage 5: Women Empowerment',text:'Women’s empowerment means that women have the knowledge, confidence and opportunity to make decisions about their own lives. Education is central to this process because it opens doors to work, health awareness and participation in public life. When a girl stays in school, she is more likely to understand her rights and contribute to her family’s income in the future. Yet many barriers remain. Poverty, early marriage, unsafe travel, household duties and old ideas about gender can interrupt education. Communities can reduce these barriers by ensuring safe transport, clean school facilities, scholarships and supportive families. Role models are also powerful. Seeing women succeed as teachers, engineers, farmers, athletes, entrepreneurs and public representatives changes what young people believe is possible. Empowerment does not mean replacing one group’s voice with another’s. It means ensuring equal respect and equal opportunity. A society that supports women’s education and leadership uses the full strength of its people.',questions:[['What does women’s empowerment include?','Knowledge, confidence and opportunity','Only money','Only travel','No decisions','Knowledge, confidence and opportunity'],['Why is education central?','It opens work and awareness opportunities','It stops rights','It creates barriers','It removes families','It opens work and awareness opportunities'],['Which can interrupt education?','Unsafe travel','Scholarships','Supportive families','Clean facilities','Unsafe travel'],['Why are role models important?','They show what is possible','They stop learning','They increase barriers','They replace schools','They show what is possible'],['Equal opportunity means:','Equal respect and chance','One group replacing another','No leadership','Only one kind of work','Equal respect and chance']]}
];
const makeEnPassageSection = passage => ({id:passage.id,title:passage.title,definition:`<b>Read the passage:</b> ${passage.text}`,support:'মনে রাখো: প্রশ্নের উত্তর passage-এর evidence থেকে দাও; নিজের বাইরের অনুমান যোগ কোরো না।',groups:[{title:'Five MCQs with answers',rule:'Read the question, find the evidence, then reject three wrong options.',examples:passage.questions.map((q,index)=>`${index+1}. ${q[0]}<br>A. ${q[1]} &nbsp; B. ${q[2]} &nbsp; C. ${q[3]} &nbsp; D. ${q[4]}<br><b>Answer: ${q[5]}</b> — This answer is directly supported by the passage.`)}],tip:'Underline names, numbers, causes and contrast words (but, however, therefore). They often lead you to the answer.',memory:'Question first, evidence next; answer only what the text suggests.',mistakes:[['Choosing an option with a familiar word','Choosing the option supported by the full idea'],['Using outside knowledge','Using passage evidence'],['Reading every line at the same speed','Slow down around key facts and contrast words']],exam:['For a main-idea question, read the opening and closing sentences again.','For vocabulary-in-context, use the nearby sentence as your clue.']});
