const en8Main = {id:'en8-technique',title:'Reading Comprehension: 5-step smart technique',definition:'A comprehension passage tests reading, not memorised facts. Read with a purpose: find topic, structure, evidence, word meaning and conclusion.',support:'মনে রাখো: passage-এ যা নেই, তা সঠিক হলেও MCQ-এর উত্তর নয়। Evidence-ই final judge।',groups:[{title:'Five steps',rule:'Use a simple time formula: 2 minutes overview + 1 minute questions + 5 minutes evidence + 2 minutes review.',examples:['Step 1: Read the title and first sentence to identify the topic.','Step 2: Notice connectors—because, however, therefore, although.','Step 3: Read each question and underline its keyword.','Step 4: Return to the exact paragraph for evidence.','Step 5: Eliminate options that are too broad, too narrow or opposite.']},{title:'Five question-type strategies',rule:'Main idea, detail, vocabulary, inference and tone each need a slightly different reading move.',examples:['Main idea: combine opening and conclusion.','Detail: locate the exact fact, number or name.','Vocabulary: read one sentence before and after.','Inference: choose only what logically follows.','Tone/purpose: notice whether the writer explains, warns, praises or compares.']}],tip:'If two options look close, choose the one that matches the passage most completely—not the one that merely sounds sensible.',memory:'Topic, clue, evidence, choice; read with purpose, use your voice.',mistakes:[['Answering from general knowledge','Answering from the written passage'],['Ignoring however/but','Treating contrast words as important turns'],['Spending too long on one question','Marking and returning after other answers']],exam:['A detail question asks “what does the passage say?”; an inference asks “what follows from it?”','Time management formula: do not sacrifice four easy questions for one difficult word.']};
