const en9Number = {id:'en9-number',title:'Number: singular and plural — 12 rules',definition:'A noun’s number tells whether it means one or more than one. Learn rule patterns, but keep a special list for irregular and foreign forms.',support:'মনে রাখো: plural করতে তাড়াহুড়ো কোরো না—শেষ বর্ণ, compound structure এবং word meaning আগে দেখো।',groups:pluralGroups.map(([title,rule,examples])=>({title,rule,examples})),tip:'The exam traps are: child/children, sheep/sheep, news/is, scissors/are, criterion/criteria and brothers-in-law.',memory:'s সাধারণ, es শেষে; y বদলে ies বেশে; f-fe ves হয়—irregular আলাদা রয়।',mistakes:[['Childs are playing.','Children are playing.'],['Sheeps are grazing.','Sheep are grazing.'],['The news are good.','The news is good.'],['A pair of shoes are new.','A pair of shoes is new.'],['Two brother-in-laws came.','Two brothers-in-law came.'],['The scissor is sharp.','The scissors are sharp.'],['Many informations arrived.','Much information arrived.'],['Criterions are important.','Criteria are important.'],['The police is alert.','The police are alert.'],['Five kilometres are far.','Five kilometres is far.']],exam:['Plural of “criterion” → <b>criteria</b>.','Choose: “The news ___ good.” → <b>is</b>.','Plural of “brother-in-law” → <b>brothers-in-law</b>.']};
const en9Gender = {id:'en9-gender',title:'Gender: 100+ pairs and common/neuter use',definition:'Gender tells whether a noun is masculine, feminine, common or neuter. Modern English often uses common-gender terms such as teacher, student and friend.',support:'মনে রাখো: object বা idea-র জন্য neuter (it); person-এর gender জানা না থাকলে common-gender noun ব্যবহার করা নিরাপদ।',table:{headers:['Masculine','Feminine'],rows:makeVocabRows(genderSeed,100,0).map(row=>row.slice(1))},filterable:true,filterLabel:'Search gender pairs',groups:[{title:'Common gender: 15 examples',rule:'These names may refer to a male or female person.',examples:['teacher','student','friend','child','parent','doctor','artist','driver','leader','neighbour','cousin','guest','singer','writer','worker']},{title:'Neuter gender: 15 examples',rule:'Non-living objects and abstract ideas are neuter; use it/its for them.',examples:['book','table','chair','river','mountain','school','car','computer','flower','city','truth','freedom','happiness','knowledge','weather']}],tip:'Actor/actress type pairs are useful in traditional grammar questions; in modern use “actor” may be common gender. Follow the form asked in the exam.',memory:'He for masculine, she for feminine; person unknown? common is fine then.',mistakes:[['He is a good actress.','She is a good actress.'],['The book lost it’s cover.','The book lost its cover.'],['Teacher is always masculine.','Teacher is common gender.'],['Child is neuter gender.','Child is common gender.'],['The sun is he in ordinary grammar.','The sun is neuter in standard modern grammar.']],exam:['Feminine of “gander” → <b>goose</b>.','Common gender example → <b>teacher</b>.','Neuter gender example → <b>book</b>.']};
const en9Degree = {id:'en9-degree',title:'Degree: positive, comparative and superlative',definition:'Positive states a quality, comparative compares two, and superlative compares more than two. The structure must change with the degree.',support:'মনে রাখো: “No other … as … as” = positive; “than any other” = comparative; “the …est/most” = superlative।',groups:[{title:'15 degree transformations',rule:'Keep the group of comparison the same.',examples:['Rina is the tallest girl in the class. → No other girl in the class is as tall as Rina.','Rina is the tallest girl in the class. → Rina is taller than any other girl in the class.','No other metal is as useful as iron. → Iron is more useful than any other metal.','No other metal is as useful as iron. → Iron is the most useful metal.','Very few cities are as busy as Kolkata. → Kolkata is one of the busiest cities.','Kolkata is one of the busiest cities. → Very few cities are as busy as Kolkata.','The Ganga is longer than most rivers. → Very few rivers are as long as the Ganga.','Very few rivers are as long as the Ganga. → The Ganga is one of the longest rivers.','Gold is more precious than most metals. → Very few metals are as precious as gold.','No other boy is as strong as Raju. → Raju is stronger than any other boy.','Raju is stronger than any other boy. → Raju is the strongest boy.','This is one of the best books. → Very few books are as good as this.','Very few students are as diligent as Mina. → Mina is one of the most diligent students.','Mount Everest is the highest peak. → No other peak is as high as Mount Everest.','No other poet is as famous as Tagore. → Tagore is more famous than any other poet.']},{title:'No other / Very few structures',rule:'No other = one clearly highest; Very few = one among a small top group.',examples:['No other bird is as fast as the eagle.','No other river is as long as the Nile.','No other player is as skilled as Rina.','No other building is as tall as this.','No other flower is as beautiful as the rose.','No other month is as cold as January.','No other animal is as faithful as the dog.','No other city is as old as Rome.','No other metal is as valuable as gold.','No other hill is as high as Everest.','Very few animals are as intelligent as dolphins.','Very few books are as useful as this one.','Very few girls are as kind as Mina.','Very few roads are as wide as this road.','Very few games are as popular as football.','Very few students are as punctual as Rina.','Very few rivers are as deep as this river.','Very few flowers are as fragrant as jasmine.','Very few machines are as useful as computers.','Very few cities are as crowded as Kolkata.']}],tip:'Do not write “more better” or “most tallest.” Use only one comparison marker: better, tallest, more useful, most useful.',memory:'No other = as…as; than any other = comparative class; the best/most = superlative pass.',mistakes:[['She is more better.','She is better.'],['He is the most tallest.','He is the tallest.'],['Rina is taller than any girl.','Rina is taller than any other girl.'],['No other boy is taller than Rina.','No other boy is as tall as Rina.'],['He is junior than me.','He is junior to me.']],exam:['Positive of “Rina is the tallest girl” → <b>No other girl is as tall as Rina.</b>','Comparative of “No other metal is as useful as iron” → <b>Iron is more useful than any other metal.</b>.','Choose correct: <b>better</b>, not more better.']};
