const tagRuleGroups = [
 ['Rule 1: positive statement → negative tag','Use the same auxiliary; if none exists, use do/does/did.',['She is ready, isn’t she?','They are late, aren’t they?','He works hard, doesn’t he?','You know him, don’t you?']],
 ['Rule 2: negative statement → positive tag','A negative clause needs a positive tag.',['She is not ready, is she?','They are not late, are they?','He does not work, does he?','You do not know him, do you?']],
 ['Rule 3: I am → aren’t I?','This is the special standard tag for I am.',['I am late, aren’t I?','I am your friend, aren’t I?','I am ready, aren’t I?']],
 ['Rule 4: Let’s → shall we?','Let’s makes a suggestion, so use shall we?',['Let’s go now, shall we?','Let’s start the lesson, shall we?','Let’s help him, shall we?']],
 ['Rule 5: imperative → will you?','Commands/requests usually take will you?',['Open the door, will you?','Please sit down, will you?','Do not make noise, will you?']],
 ['Rule 6: negative pronouns','Nobody, no one, nothing, few, little are negative in sense; use a positive tag.',['Nobody came, did they?','Nothing happened, did it?','Few people know, do they?','Little is left, is it?']],
 ['Rule 7: everyone/everybody/someone','Use they in the tag for indefinite people.',['Everyone is ready, aren’t they?','Somebody called, didn’t they?','Nobody knows, do they?']],
 ['Rule 8: used to','Use did/didn’t with used to.',['He used to play, didn’t he?','She did not use to sing, did she?','They used to live here, didn’t they?']],
 ['Rule 9: ought to','Use ought/oughtn’t in the tag.',['He ought to go, oughtn’t he?','We ought not to wait, ought we?','She ought to study, oughtn’t she?']],
 ['Rule 10: need not / dare not','When need/dare act as modals, repeat them.',['You need not wait, need you?','He dare not speak, dare he?','We need not hurry, need we?']],
 ['Rule 11: have to / has to','Use do/does because have to is not the perfect auxiliary here.',['She has to leave, doesn’t she?','They have to work, don’t they?','He does not have to go, does he?']],
 ['Rule 12: had better','Use had/hadn’t in the tag.',['You had better go, hadn’t you?','He had better not wait, had he?','We had better leave, hadn’t we?']],
 ['Rule 13: there is/are','Repeat there in the tag.',['There is a book, isn’t there?','There are chairs, aren’t there?','There was no bus, was there?']],
 ['Rule 14: this/that/these/those','This/that → it; these/those → they.',['This is your pen, isn’t it?','That was easy, wasn’t it?','These are new, aren’t they?','Those were old, weren’t they?']],
 ['Rule 15: special words','Few/little are negative; a few/a little are positive.',['Few students came, did they?','A few students came, didn’t they?','Little water remains, is it?','A little water remains, doesn’t it?']]
];
const conditionalGroups = [
 {title:'Zero Conditional',rule:'If/when + present simple, present simple. Use for facts, habits and general truths.',examples:['If you heat ice, it melts.','If it rains, the ground gets wet.','If people eat too much, they gain weight.','When the sun sets, it gets dark.','If you mix red and blue, you get purple.','If I drink tea at night, I cannot sleep.','If plants do not get water, they die.','When water reaches 100°C, it boils.','If children are tired, they sleep early.','If you press this button, the light turns on.']},
 {title:'First Conditional',rule:'If + present simple, will + V1. Use for real possible future results.',examples:['If it rains, we will stay home.','If you study, you will pass.','If she calls, I will answer.','If they come early, we will start.','If you work hard, you will improve.','If the bus is late, I will walk.','If he apologises, I will forgive him.','If we save water, we will help the village.','If the shop opens, I will buy a pen.','If you do not hurry, you will miss the train.']},
 {title:'Second Conditional',rule:'If + past simple, would + V1. Use for unreal or unlikely present/future situations.',examples:['If I were rich, I would help the poor.','If she had time, she would learn music.','If I knew the answer, I would tell you.','If they lived nearby, we would meet often.','If he were taller, he would play basketball.','If I were you, I would revise daily.','If it were not raining, we would go out.','If she spoke English well, she would get the job.','If we had a car, we would travel more.','If he studied, he would pass.']},
 {title:'Third Conditional',rule:'If + past perfect, would have + V3. Use for unreal past situations and regrets.',examples:['If I had studied, I would have passed.','If she had called, I would have helped.','If they had left early, they would have caught the train.','If he had listened, he would have understood.','If it had not rained, we would have played.','If I had known, I would have told you.','If she had worked hard, she would have won.','If we had saved money, we would have bought a house.','If he had worn a helmet, he would have been safe.','If you had asked, I would have explained.']},
 {title:'Mixed Conditional',rule:'Mix past condition with present result, or present condition with past result, when time is different.',examples:['If I had studied medicine, I would be a doctor now.','If she had taken the bus, she would be here now.','If they had saved water, the pond would not be dry now.','If I were more careful, I would not have lost the key.','If he were honest, he would not have lied yesterday.','If we were richer, we would have travelled last year.','If she had accepted the job, she would live in Kolkata now.','If I had slept early, I would feel fresh now.','If they were punctual, they would not have missed the train.','If he had trained, he would be stronger now.']},
 {title:'Unless vs If not',rule:'Unless = if not. Do not use another not after unless in a normal affirmative condition.',examples:['Unless you study, you will not pass.','If you do not study, you will not pass.','Unless it rains, we will go.','If it does not rain, we will go.','Unless you hurry, you will miss the bus.','If you do not hurry, you will miss the bus.','Unless he apologises, I will not forgive him.','If he does not apologise, I will not forgive him.','Unless we save water, there will be shortage.','If we do not save water, there will be shortage.']}
];
