const en10Main = {id:'en10-tags',title:'Question Tags: 15 special rules and 50 practice sentences',definition:'A question tag is a short question added to a statement to seek agreement or confirmation. Match the auxiliary, tense, pronoun and positive/negative pattern.',support:'মনে রাখো: বাক্য positive হলে tag negative; বাক্য negative হলে tag positive। আগে helping verb খুঁজে নাও।',groups:tagRuleGroups,tip:'Tag বসানোর আগে বাক্যের subject-কে pronoun-এ বদলাও: Rina → she, books → they, this → it.',memory:'Positive line, negative tail; negative line, positive trail.',mistakes:[['She is ready, is she?','She is ready, isn’t she?'],['He does not come, doesn’t he?','He does not come, does he?'],['Let’s go, will we?','Let’s go, shall we?'],['I am late, am not I?','I am late, aren’t I?'],['Nobody came, didn’t they?','Nobody came, did they?']],exam:['Add tag: “Rina sings well, ___?” → <b>doesn’t she</b>.','Add tag: “They are not late, ___?” → <b>are they</b>.','Add tag: “Open the door, ___?” → <b>will you</b>.']};
