function buildMcqMarathonRows(chapter) {
  const source=buildNewChapterExamples(chapter);
  const concepts=source.map(row=>row[2]);
  return Array.from({length:50},(_,index)=>{
    const row=source[index];
    const correct=row[2];
    const wrong=[concepts[(index+13)%concepts.length],concepts[(index+29)%concepts.length],concepts[(index+47)%concepts.length]];
    const choices=[...wrong];
    const answerIndex=index%4;
    choices.splice(answerIndex,0,correct);
    const letters=['A','B','C','D'];
    const optionLine=choices.map((choice,choiceIndex)=>`${letters[choiceIndex]}. ${choice}`).join(' | ');
    return [String(index+1),`Question: ${row[1]}`,optionLine,`${letters[answerIndex]}. ${correct} — ${row[3]}`];
  });
}

