function getChapter(id){return [...DATA.bengali.chapters,...DATA.english.chapters].find(chapter=>chapter.id===id);}
function ttsButton(text){return `<button class="mini-action" type="button" data-action="tts" data-text="${attr(text.replace(/<[^>]*>/g,''))}" aria-label="Read aloud">🔊</button>`;}
function bookmarkButton(chapter,section,type,text,index){const id=`${chapter.id}-${section.id}-${type}-${index}`;return `<button class="mini-action" type="button" data-action="bookmark" data-bookmark-id="${attr(id)}" data-bookmark-hub="${chapter.hub}" data-bookmark-chapter="${chapter.id}" data-bookmark-type="${type}" data-bookmark-text="${attr(text.replace(/<[^>]*>/g,''))}" aria-label="Bookmark this ${type}">⭐</button>`;}
function renderExamples(chapter,section,examples){return `<ol class="example-list">${examples.map((example,index)=>`<li><span class="example-text">${example}</span>${ttsButton(example)}${bookmarkButton(chapter,section,'example',example,index)}</li>`).join('')}</ol>`;}
function renderMistakes(pairs){return `<div class="mistake-box"><h3>⚠️ সাধারণ ভুল / Common mistakes</h3>${pairs.map(pair=>`<div class="error-pair"><span class="wrong">✗ ${escapeHTML(pair[0])}</span><i>→</i><span class="right">✓ ${escapeHTML(pair[1])}</span></div>`).join('')}</div>`;}
function renderExam(exam){return `<div class="exam-box"><h3>📝 পরীক্ষায় যেভাবে আসে / How It Appears in Exam</h3>${exam.map((item,index)=>`<div class="exam-question"><b>${index+1}.</b> ${item}</div>`).join('')}</div>`;}
function findSectionById(sectionId) {
  for (const chapter of [...DATA.bengali.chapters, ...DATA.english.chapters]) {
    const section = chapter.sections.find(item => item.id === sectionId);
    if (section) return section;
  }
  return null;
}

function tableRowHTML(row) {
  return `<tr data-vocab-row data-search="${attr(row.join(' '))}">${row.map(cell => `<td>${escapeHTML(cell)}</td>`).join('')}</tr>`;
}

function tableBodyHTML(rows) {
  return rows.map(tableRowHTML).join('');
}

function renderDataTable(section) {
  const rows = section.table.rows || [];
  const preferredSize=Number(StorageManager.get('peh_tablePageSize',50)) || 50;
  const initial = Math.min(rows.length,Math.max(25,preferredSize));
  const isLarge = rows.length > initial;
  return `${section.filterable ? `<div class="vocab-filter"><label for="filter-${section.id}">🔎 ${section.filterLabel || 'Search this list'}</label><input id="filter-${section.id}" type="search" data-action="vocab-filter" data-table="${section.id}" placeholder="Type a word to filter…" autocomplete="off"></div>` : ''}
    <p id="table-status-${section.id}" class="table-status" aria-live="polite">Showing ${initial} of ${rows.length} entries</p>
    <div class="comparison-wrap"><table class="comparison-table" data-vocab-table="${section.id}" data-visible-count="${initial}"><thead><tr>${section.table.headers.map(heading => `<th>${escapeHTML(heading)}</th>`).join('')}</tr></thead><tbody>${tableBodyHTML(rows.slice(0, initial))}</tbody></table></div>
    ${isLarge ? `<div class="table-actions"><button type="button" class="btn btn-secondary" data-action="table-more" data-table="${section.id}">Load 50 more entries</button></div>` : ''}`;
}

function renderSection(chapter, section) {
  return `<section id="${section.id}" class="lesson-section reveal">
    <h2 class="section-title">${escapeHTML(section.title)}</h2>
    <div class="definition-box"><h3>📌 সহজ সংজ্ঞা</h3><p>${section.definition}</p>${section.support ? `<p class="bn-support">${escapeHTML(section.support)}</p>` : ''}${bookmarkButton(chapter, section, 'rule', section.definition, 0)}</div>
    ${section.formula ? `<div class="formula-box"><h3>Formula</h3><p>${escapeHTML(section.formula)}</p></div>` : ''}
    ${section.groups ? section.groups.map(group => `<article class="rule-card"><h3>${escapeHTML(group.title)}</h3><p>${group.rule}</p>${renderExamples(chapter, section, group.examples || [])}</article>`).join('') : ''}
    ${section.table ? renderDataTable(section) : ''}
    ${section.tip ? `<div class="tip-box"><h3>💡 Teacher’s shortcut</h3><p>${escapeHTML(section.tip)}</p>${bookmarkButton(chapter, section, 'tip', section.tip, 1)}</div>` : ''}
    ${section.memory ? `<div class="memory-box"><h3>🎵 মনে রাখার ছড়া / Memory hook</h3><p>${escapeHTML(section.memory)}</p></div>` : ''}
    ${section.mistakes ? renderMistakes(section.mistakes) : ''}
    ${section.exam ? renderExam(section.exam) : ''}
  </section>`;
}

function renderTableFilter(sectionId, query) {
  const section = findSectionById(sectionId);
  const table = document.querySelector(`[data-vocab-table="${sectionId}"]`);
  if (!section || !table) return;
  const normalized = query.trim().toLowerCase();
  const rows = normalized ? section.table.rows.filter(row => row.join(' ').toLowerCase().includes(normalized)) : section.table.rows;
  const visible = normalized ? rows.length : Math.min(rows.length, Number(table.dataset.visibleCount || 50));
  const body = $('tbody', table);
  if (body) body.innerHTML = tableBodyHTML(rows.slice(0, visible));
  const status = $(`#table-status-${sectionId}`);
  if (status) status.textContent = normalized ? `${rows.length} matching entries` : `Showing ${visible} of ${rows.length} entries`;
  const more = $(`[data-action="table-more"][data-table="${sectionId}"]`);
  if (more) more.hidden = Boolean(normalized) || visible >= rows.length;
}

function loadMoreTable(sectionId) {
  const section = findSectionById(sectionId);
  const table = document.querySelector(`[data-vocab-table="${sectionId}"]`);
  if (!section || !table) return;
  const preferredSize=Number(StorageManager.get('peh_tablePageSize',50)) || 50;
  const current = Number(table.dataset.visibleCount || preferredSize);
  const next = Math.min(section.table.rows.length, current + Math.max(25,preferredSize));
  table.dataset.visibleCount = String(next);
  const body = $('tbody', table);
  if (body) body.innerHTML = tableBodyHTML(section.table.rows.slice(0, next));
  const status = $(`#table-status-${sectionId}`);
  if (status) status.textContent = `Showing ${next} of ${section.table.rows.length} entries`;
  const more = $(`[data-action="table-more"][data-table="${sectionId}"]`);
  if (more && next >= section.table.rows.length) more.hidden = true;
}

