const DictionaryManager = {
  getAll(){return StorageManager.get('peh_dictionary',[]);},
  add(word,meaning,sentence){
    const cleanWord=word.trim();const cleanMeaning=meaning.trim();
    if(!cleanWord||!cleanMeaning){GamificationEngine.toast('Word and meaning are both required.');return;}
    const all=this.getAll();const id=`dict-${cleanWord.toLowerCase()}-${Date.now()}`;
    all.unshift({id,word:cleanWord,meaning:cleanMeaning,sentence:sentence.trim(),date:TODAY()});
    StorageManager.set('peh_dictionary',all.slice(0,500));this.renderList();
  },
  remove(id){StorageManager.set('peh_dictionary',this.getAll().filter(item=>item.id!==id));this.renderList();},
  clear(){if(window.confirm('Clear your personal dictionary?')){StorageManager.set('peh_dictionary',[]);this.renderList();}},
  renderList(query=''){
    const target=$('#dictionary-list');if(!target)return;
    const q=query.trim().toLowerCase();const items=this.getAll().filter(item=>!q||`${item.word} ${item.meaning} ${item.sentence}`.toLowerCase().includes(q));
    target.innerHTML=items.length?items.map(item=>`<article class="dictionary-item"><div><h3>${escapeHTML(item.word)}</h3><p><b>Meaning:</b> ${escapeHTML(item.meaning)}</p>${item.sentence?`<p class="muted"><b>My sentence:</b> ${escapeHTML(item.sentence)}</p>`:''}<small>Saved: ${item.date}</small></div><div class="dictionary-actions"><button class="mini-action" type="button" data-action="dictionary-speak" data-word="${attr(item.word)}" aria-label="Speak word">🔊</button><button class="mini-action" type="button" data-action="dictionary-remove" data-id="${attr(item.id)}" aria-label="Remove word">×</button></div></article>`).join(''):`<div class="empty-state"><span>📖</span><p>নিজের প্রথম word যোগ করুন। নতুন word, Bengali meaning এবং নিজের sentence লিখুন।</p></div>`;
  },
  view(){return `<div class="page-shell"><p class="section-kicker">Your words, your revision</p><h1 class="section-title">📖 Personal Dictionary</h1><section class="glass-card dictionary-form"><h2>নতুন Word যোগ করুন</h2><div class="dictionary-inputs"><input id="dictionary-word" type="text" maxlength="80" placeholder="Word / শব্দ"><input id="dictionary-meaning" type="text" maxlength="180" placeholder="Meaning / অর্থ"><input id="dictionary-sentence" type="text" maxlength="260" placeholder="My sentence (optional)"><button class="btn btn-primary" type="button" data-action="dictionary-add">+ Save word</button></div><p class="muted">Tip: প্রতিটি word-এর নিজের sentence লিখলে vocabulary দীর্ঘদিন মনে থাকে।</p></section><section class="glass-card"><div class="panel-header"><h2>Saved Words</h2><button class="btn btn-ghost" type="button" data-action="dictionary-clear">Clear all</button></div><input id="dictionary-search" class="page-search-input" type="search" placeholder="Search your saved words"><div id="dictionary-list" class="dictionary-list"></div></section></div>`;}
};

