function buildPlanRows(days){
  const chapters=[...DATA.bengali.chapters,...DATA.english.chapters];
  const tasks=['Read Book Mode theory + shortcut','Read 25 One-Line examples aloud','Complete 25 Detailed examples','Attempt 15 MCQs and record mistakes','Revise flashcards + bookmark weak rules'];
  return Array.from({length:days},(_,index)=>{const day=index+1;const chapter=chapters[index%chapters.length];const task=tasks[index%tasks.length];const phase=day<=Math.ceil(days*.4)?'Foundation':day<=Math.ceil(days*.75)?'Practice':'Revision & Mock';return `<tr><td>Day ${day}</td><td>${phase}</td><td>${chapter.icon} ${escapeHTML(chapter.title)}</td><td>${task}</td></tr>`;}).join('');
}
const StudyPlanHub = {
  view(){return `<div class="page-shell"><p class="section-kicker">Free structured preparation</p><h1 class="section-title">🗓 30 / 60 / 90 Day Study Plans</h1><section class="glass-card"><h2>কীভাবে plan বেছে নেবেন</h2><p><b>90 দিন:</b> প্রথমবার সম্পূর্ণ syllabus। <b>60 দিন:</b> syllabus + practice। <b>30 দিন:</b> revision, MCQ এবং mistake correction।</p><p class="muted">প্রতিদিন planner-এ নিজের completed task mark করুন। কোনো দিন miss হলে পরের দিনে double load নেবেন না—plan shift করুন।</p></section>${[30,60,90].map(days=>`<details class="study-plan-details glass-card" ${days===30?'open':''}><summary><b>${days}-Day Plan</b> <span>${days===30?'Crash Revision':days===60?'Practice + Revision':'Complete Foundation Plan'}</span></summary><div class="comparison-wrap"><table class="comparison-table"><thead><tr><th>Day</th><th>Phase</th><th>Chapter</th><th>Daily task</th></tr></thead><tbody>${buildPlanRows(days)}</tbody></table></div></details>`).join('')}</div>`;}
};

const PlannerManager = {
  getAll(){return StorageManager.get('peh_planner',[]);},
  add(title,chapter){
    const clean=title.trim();
    if(!clean){GamificationEngine.toast('Write a study task first.');return;}
    const items=this.getAll();
    items.unshift({id:`plan-${Date.now()}`,title:clean,chapter,done:false,date:TODAY()});
    StorageManager.set('peh_planner',items.slice(0,100));
    this.renderList();
  },
  toggle(id){const items=this.getAll().map(item=>item.id===id?{...item,done:!item.done}:item);StorageManager.set('peh_planner',items);this.renderList();},
  remove(id){StorageManager.set('peh_planner',this.getAll().filter(item=>item.id!==id));this.renderList();},
  renderList(){
    const target=$('#planner-list');if(!target)return;
    const items=this.getAll();
    target.innerHTML=items.length?items.map(item=>`<article class="planner-item ${item.done?'is-done':''}"><label><input type="checkbox" data-action="planner-toggle" data-id="${attr(item.id)}" ${item.done?'checked':''}><span><b>${escapeHTML(item.title)}</b><small>${escapeHTML(getChapter(item.chapter)?.title||item.chapter)} · ${item.date}</small></span></label><button class="mini-action" type="button" data-action="planner-delete" data-id="${attr(item.id)}" aria-label="Delete task">×</button></article>`).join(''):`<div class="empty-state"><span>📅</span><p>আজকের প্রথম study task যোগ করুন। ছোট task শেষ করলে progress বাড়ে।</p></div>`;
  },
  view(){
    const chapters=[...DATA.bengali.chapters,...DATA.english.chapters];
    return `<div class="page-shell"><p class="section-kicker">Plan · practise · revise</p><h1 class="section-title">📅 Daily Study Planner</h1><section class="glass-card planner-form"><h2>আজকের Task যোগ করুন</h2><div class="planner-inputs"><input id="planner-title" type="text" maxlength="140" placeholder="Example: BN-CH2 সন্ধির 25টি example revise করুন"><select id="planner-chapter" aria-label="Choose chapter">${chapters.map(chapter=>`<option value="${chapter.id}">${chapter.hub==='bn'?'🅱':'🇬🇧'} ${chapter.number}. ${escapeHTML(chapter.title)}</option>`).join('')}</select><button type="button" class="btn btn-primary" data-action="planner-add">+ Add task</button></div><p class="muted">Suggested rhythm: 25 min theory → 25 examples → 10 MCQ → 5 min mistake revision.</p></section><section class="glass-card"><div class="panel-header"><h2>আজকের ও আগের Tasks</h2><button class="btn btn-ghost" type="button" data-action="planner-clear-done">Clear completed</button></div><div id="planner-list" class="planner-list"></div></section></div>`;
  }
};

const MistakeManager = {
  getAll(){return StorageManager.get('peh_mistakes',[]);},
  add(question){
    if(!question?.id)return;
    const all=this.getAll();
    const existing=all.find(item=>item.id===question.id);
    const entry={id:question.id,chapter:question.chapter,hub:question.hub,question:question.question,correct:question.options?.[question.answer]||'',explanation:question.explanation||'',date:TODAY(),count:(existing?.count||0)+1};
    const next=[entry,...all.filter(item=>item.id!==question.id)].slice(0,200);
    StorageManager.set('peh_mistakes',next);
  },
  remove(id){StorageManager.set('peh_mistakes',this.getAll().filter(item=>item.id!==id));this.renderList();},
  clear(){if(window.confirm('Clear all mistake-notebook entries?')){StorageManager.set('peh_mistakes',[]);this.renderList();}},
  renderList(){
    const target=$('#mistake-list');if(!target)return;
    const items=this.getAll();
    target.innerHTML=items.length?items.map(item=>`<article class="mistake-note"><div><small>${item.hub==='bn'?'🅱 বাংলা':'🇬🇧 English'} · ${escapeHTML(getChapter(item.chapter)?.title||item.chapter)} · missed ${item.count} time(s)</small><p><b>Q.</b> ${escapeHTML(item.question)}</p><p class="right"><b>Correct:</b> ${escapeHTML(item.correct)}</p><p class="muted">${escapeHTML(item.explanation)}</p></div><button class="mini-action" type="button" data-action="mistake-remove" data-id="${attr(item.id)}" aria-label="Remove mistake note">×</button></article>`).join(''):`<div class="empty-state"><span>🧠</span><p>এখনও কোনও ভুল সংরক্ষিত নেই। Quiz-এ ভুল করলে তা এখানে automatic save হবে।</p></div>`;
  },
  view(){return `<div class="page-shell"><p class="section-kicker">Turn mistakes into marks</p><h1 class="section-title">🧠 Mistake Notebook</h1><section class="glass-card"><div class="panel-header"><div><h2>ভুল থেকে Revision</h2><p class="muted">প্রতিটি ভুল question-এর correct answer ও explanation এখানে থাকে। একই ভুল কতবার হয়েছে তাও দেখা যাবে।</p></div><button class="btn btn-ghost" type="button" data-action="mistake-clear">Clear notebook</button></div><div id="mistake-list" class="mistake-list"></div></section></div>`;}
};

function showShortcutsModal(){
  showModal(`<div class="modal"><h2>⌨ Keyboard Shortcuts</h2><div class="shortcut-grid"><p><kbd>/</kbd> Search focus</p><p><kbd>Esc</kbd> Close panel/modal</p><p><kbd>Space</kbd> Flip flashcard</p><p><kbd>←</kbd> Previous flashcard</p><p><kbd>→</kbd> Next flashcard</p><p><kbd>R</kbd> Mark flashcard again</p><p><kbd>Tab</kbd> Move through controls</p><p><kbd>Enter</kbd> Activate focused button</p></div><div class="modal-actions"><button class="btn btn-primary" data-action="close-modal">Got it</button></div></div>`);
}

const Router = {
  current:'',
  renderTimer:null,
  init(){
    window.addEventListener('hashchange',()=>this.loadView(location.hash));
    this.loadView(location.hash||'#home');
  },
  navigate(hash){ location.hash=hash; },
  unmountView(){
    QuizEngine.reset();
    MockTestEngine.stopTimer();
    TTSEngine.stop();
  },
  loadView(hash){
    const route=hash||'#home';
    const known=['#home','#mock-test-bn','#mock-test-en','#mock-test-mega','#flashcards-bn','#flashcards-en','#bookmarks','#progress','#notes','#planner','#mistakes','#revision','#study-plan','#dictionary','#daily-challenge','#word-of-day','#search-results'];
    const chapter=getChapter(route.slice(1));
    if(!known.includes(route)&&!chapter){
      if(location.hash!=='#home') location.hash='#home';
      return;
    }
    clearTimeout(this.renderTimer);
    SettingsManager.close();
    this.unmountView();
    APP.classList.add('is-leaving');
    APP.setAttribute('aria-busy','true');
    APP.innerHTML='<div class="page-shell route-loading"><section class="glass-card"><p class="section-kicker">Preparing your lesson</p><h2>পাঠ্যবস্তু লোড হচ্ছে…</h2><p class="muted">অল্প অপেক্ষা করুন। বড় vocabulary তালিকা ধাপে ধাপে দেখানো হবে।</p></section></div>';
    this.renderTimer=setTimeout(()=>{
      let html='';
      if(route==='#home') html=HubContentRenderer.renderHomepage();
      else if(chapter){
        StorageManager.set('peh_activeHub',chapter.hub);
        HubSwitcher.apply(chapter.hub);
        html=HubContentRenderer.renderChapterPage(chapter.id);
      } else if(route.startsWith('#mock-test-')) html=HubContentRenderer.renderMockTestPage(route.replace('#mock-test-',''));
      else if(route.startsWith('#flashcards-')) html=HubContentRenderer.renderFlashcardPage(route.replace('#flashcards-',''));
      else if(route==='#bookmarks') html=this.bookmarksView();
      else if(route==='#progress') html=this.progressView();
      else if(route==='#notes') html=this.notesView();
      else if(route==='#planner') html=PlannerManager.view();
      else if(route==='#mistakes') html=MistakeManager.view();
      else if(route==='#revision') html=RevisionHub.view();
      else if(route==='#study-plan') html=StudyPlanHub.view();
      else if(route==='#dictionary') html=DictionaryManager.view();
      else if(route==='#daily-challenge') html=this.dailyView();
      else if(route==='#word-of-day') html=this.wordView();
      else if(route==='#search-results') html=this.searchResultsView();
      else html=HubContentRenderer.renderNotFound();
      APP.innerHTML=html;
      APP.classList.remove('is-leaving');
      APP.setAttribute('aria-busy','false');
      this.current=route;
      window.scrollTo({top:0,behavior:'auto'});
      this.mountView(route,chapter);
    },160);
  },
  mountView(route,chapter){
    ScrollAnimations.init(APP);
    if(route==='#home'){
      FloatingBackground.init();
      TypewriterEffect.init();
      CounterAnimation.init(APP);
      WordOfDay.init();
      DailyChallenge.init();
    }
    if(chapter){
      CustomScrollSpy.init();
      if(chapter.quiz.length) QuizEngine.init(chapter.id,chapter.quiz.map((q,i)=>toQuestion(q,chapter.id,chapter.hub,i)));
    }
    if(route.startsWith('#flashcards-')){
      const hub=route.replace('#flashcards-','');
      const selected=hub==='bn'?getChapter('bn-ch2'):getChapter('en-ch2');
      FlashcardEngine.init(selected.id,selected.flashcards);
    }
    if(route==='#bookmarks') BookmarkManager.renderBookmarksPage();
    if(route==='#progress') ProgressDashboard.init();
    if(route==='#notes') { NotesManager.syncRoute(); DrawingCanvas.init(); }
    if(route==='#planner') PlannerManager.renderList();
    if(route==='#mistakes') MistakeManager.renderList();
    if(route==='#dictionary') DictionaryManager.renderList();
    if(route==='#daily-challenge') DailyChallenge.init();
    if(route==='#word-of-day') WordOfDay.init();
    if(route==='#search-results') {
      const input=$('#page-search');
      if(input) input.focus();
    }
    GamificationEngine.updateUI();
  },
  bookmarksView(){
    return `<div class="page-shell"><h1 class="section-title">⭐ My Bookmarks</h1><div class="glass-card"><div class="bookmark-filters"><select id="bookmark-hub" aria-label="Filter bookmarks by hub"><option value="all">All hubs</option><option value="bn">বাংলা হাব</option><option value="en">English Hub</option></select><input id="bookmark-search" type="search" placeholder="Search saved items" aria-label="Search bookmarks"><button class="btn btn-ghost" type="button" data-action="print-page">🖨️ Print</button><button class="btn btn-ghost" type="button" data-action="bookmark-clear">Remove all</button></div><div id="bookmarks-list"></div></div></div>`;
  },
  progressView(){
    return `<div class="page-shell"><h1 class="section-title">📊 আমার অগ্রগতি / My Progress</h1><section class="progress-summary glass-card"><div id="overall-ring" class="overall-ring" style="--progress:0"></div><div id="xp-summary"></div></section><section id="chapter-progress" class="dual-progress"></section><section class="glass-card"><h2 class="section-title">🔥 Last 30 days</h2><div id="streak-calendar" class="calendar-grid"></div></section><section class="glass-card"><h2 class="section-title">Quiz Score History</h2><div id="quiz-history" class="chart-bars"></div></section><section class="glass-card"><h2 class="section-title">🎖️ Badges</h2><div id="badge-grid" class="badge-grid"></div></section><div class="modal-actions"><button class="btn btn-secondary" type="button" data-action="print-page">Export Progress Report</button></div></div>`;
  },
  notesView(){
    return `<div class="page-shell"><h1 class="section-title">📝 Personal Notes & Practice</h1><section class="glass-card route-notes-card"><div class="panel-header"><div><p class="section-kicker">Autosaved in this browser</p><h2>আমার নোট / My Notes</h2></div><button class="btn btn-ghost" type="button" data-action="print-notes">🖨️ Print notes</button></div><div class="notes-toolbar" role="toolbar" aria-label="Note formatting"><button type="button" data-action="notes-bold"><b>B</b></button><button type="button" data-action="notes-italic"><i>I</i></button><button type="button" data-action="notes-bullet">• List</button><button type="button" data-action="notes-heading">H</button><button type="button" data-action="notes-copy">Copy</button><button type="button" data-action="notes-cut">Cut</button><button type="button" data-action="clear-notes">Clear</button></div><label class="sr-only" for="route-notes-text">Write your personal notes</label><textarea id="route-notes-text" class="route-notes-text" placeholder="আজ কী শিখলে? / What did you learn today?"></textarea><div class="notes-meta"><span id="route-notes-count">0 words · 0 characters</span><span id="route-notes-saved">Autosave ready</span></div></section><section class="glass-card"><h2 class="section-title">✍️ Practice Canvas</h2><p id="canvas-prompt">${StorageManager.get('peh_activeHub','bn')==='bn'?'লিখুন: বিশেষ্য পদ':'Practice: accommodation'}</p><div class="canvas-tools"><button type="button" data-action="canvas-pen">✏️ Pen</button><button type="button" data-action="canvas-eraser">⌫ Eraser</button><input type="color" value="#00b4ff" data-action="canvas-color" aria-label="Brush colour"><label>Size <input type="range" min="1" max="30" value="4" data-action="canvas-size" aria-label="Brush size"></label><button type="button" data-action="canvas-undo">Undo</button><button type="button" data-action="canvas-redo">Redo</button><button type="button" data-action="canvas-clear">Clear</button><button type="button" data-action="canvas-save">Save PNG</button></div><div class="canvas-wrap"><canvas id="practice-canvas" width="600" height="300" aria-label="Handwriting practice canvas"></canvas></div></section></div>`;
  },
  dailyView(){ return `<div class="page-shell"><h1 class="section-title">🎯 Daily Challenge</h1><section id="daily-challenge" class="glass-card"></section></div>`; },
  wordView(){ return `<div class="page-shell"><h1 class="section-title">💎 Word of the Day</h1><section class="glass-card wotd"><div id="wotd-content"></div></section><section class="glass-card"><h2>Pronunciation practice</h2><label for="pronounce-input">Type an English word</label><div class="hero-actions"><input id="pronounce-input" class="search-input visible-input" type="text" placeholder="e.g. accommodation"><button class="btn btn-secondary" type="button" data-action="pronounce-input">🔊 Pronounce</button></div><p class="muted">Try: accommodation /əˌkɒməˈdeɪʃən/, comfortable /ˈkʌmftəbl/, vegetable /ˈvedʒtəbl/.</p></section></div>`; },
  searchResultsView(){ return `<div class="page-shell"><p class="section-kicker">Search both hubs</p><h1 class="section-title">🔎 Search Results</h1><section class="glass-card"><label for="page-search">বাংলা বা English grammar topic লিখুন</label><input id="page-search" class="page-search-input" type="search" autocomplete="off" placeholder="Example: সন্ধি, tense, article, preposition"><div id="page-search-results" class="page-search-results"><p class="muted">কমপক্ষে 2টি অক্ষর লিখুন। ফলাফল chapter অনুযায়ী দেখা যাবে।</p></div></section></div>`; }
};

function showModal(html){$('#modal-root').innerHTML=html;}
function closeModal(){$('#modal-root').innerHTML='';}
function closeDrawer(){const drawer=$('#mobile-drawer');drawer.classList.remove('is-open');drawer.setAttribute('aria-hidden','true');$('#drawer-toggle').setAttribute('aria-expanded','false');$('#drawer-scrim').hidden=true;}
function openDrawer(){const drawer=$('#mobile-drawer');drawer.classList.add('is-open');drawer.setAttribute('aria-hidden','false');$('#drawer-toggle').setAttribute('aria-expanded','true');$('#drawer-scrim').hidden=false;}
function markChapterComplete(id){const p=StorageManager.get('peh_chapterProgress',{});if(p[id]===100)return;p[id]=100;StorageManager.set('peh_chapterProgress',p);const read=StorageManager.get('peh_chaptersRead',[]);if(!read.includes(id))read.push(id);StorageManager.set('peh_chaptersRead',read);GamificationEngine.addXP(id.startsWith('bn')?50:75,'Chapter completed');GamificationEngine.checkBadgeConditions();ConfettiEffect.burst(window.innerWidth/2,200);Router.loadView(location.hash);}

function eventHub(){document.addEventListener('click',event=>{const target=event.target.closest('[data-action],[data-route]');if(!target)return;const action=target.dataset.action;if(target.dataset.route){event.preventDefault();Router.navigate(target.dataset.route);closeDrawer();return;}switch(action){case 'close-modal':closeModal();break;case 'focus-search':SearchEngine.focusSearch();break;case 'close-drawer':closeDrawer();break;case 'close-settings':SettingsManager.close();break;case 'settings-reset':SettingsManager.reset();break;case 'open-shortcuts':SettingsManager.close();showShortcutsModal();break;case 'focus-toggle':FocusManager.toggle();break;case 'open-notes':SettingsManager.close();NotesManager.open();break;case 'close-notes':NotesManager.close();break;case 'open-pomodoro':PomodoroTimer.open();break;case 'start-hub':HubSwitcher.switchTo(target.dataset.hub);break;case 'select-home-hub':StorageManager.set('peh_activeHub',target.dataset.hub);HubSwitcher.apply(target.dataset.hub);$('#home-chapter-grid').innerHTML=HubContentRenderer.renderHomepageChapterCards(target.dataset.hub);$$('.hub-select-card').forEach(button=>button.classList.toggle('is-active',button.dataset.hub===target.dataset.hub));ScrollAnimations.init($('#home-chapter-grid'));break;case 'tts':TTSEngine.speak(unattr(target.dataset.text));break;case 'bookmark':BookmarkManager.add({id:unattr(target.dataset.bookmarkId),hub:target.dataset.bookmarkHub,chapter:target.dataset.bookmarkChapter,type:target.dataset.bookmarkType,text:unattr(target.dataset.bookmarkText)});break;case 'table-more':loadMoreTable(target.dataset.table);break;case 'chapter-complete':markChapterComplete(target.dataset.chapter);break;case 'print-page':window.print();break;case 'quiz-choice':QuizEngine.handleAnswer(Number(target.dataset.option));break;case 'quiz-next':QuizEngine.next();break;case 'quiz-prev':QuizEngine.prev();break;case 'quiz-retry':{const chapter=getChapter(QuizEngine.chapterId);if(chapter)QuizEngine.init(chapter.id,chapter.quiz.map((q,i)=>toQuestion(q,chapter.id,chapter.hub,i)));break;}case 'flash-flip':FlashcardEngine.flip();break;case 'flash-known':FlashcardEngine.markKnown();break;case 'flash-again':FlashcardEngine.markAgain();break;case 'flash-next':FlashcardEngine.next();break;case 'flash-prev':FlashcardEngine.prev();break;case 'flash-restart':{const ch=getChapter(FlashcardEngine.setId);FlashcardEngine.init(ch.id,ch.flashcards);break;}case 'flash-set':{const ch=getChapter(target.dataset.chapter);if(ch){$$('.subtype-tab').forEach(b=>b.classList.toggle('is-selected',b===target));FlashcardEngine.init(ch.id,ch.flashcards);}break;}case 'start-mock':MockTestEngine.init(target.dataset.type);break;case 'mock-choice':MockTestEngine.handleAnswer(Number(target.dataset.option));break;case 'mock-jump':MockTestEngine.jumpToQuestion(Number(target.dataset.index));break;case 'mock-prev':MockTestEngine.jumpToQuestion(Math.max(0,MockTestEngine.index-1));break;case 'mock-next':MockTestEngine.jumpToQuestion(Math.min(MockTestEngine.questions.length-1,MockTestEngine.index+1));break;case 'mock-mark':MockTestEngine.markForReview();break;case 'mock-submit':if(window.confirm('Submit this test now?'))MockTestEngine.submitTest();break;case 'mock-retry':MockTestEngine.init(MockTestEngine.type);break;case 'bookmark-remove':BookmarkManager.remove(unattr(target.dataset.id));break;case 'bookmark-go':BookmarkManager.navigateToBookmark(unattr(target.dataset.id));break;case 'bookmark-clear':if(window.confirm('Remove all bookmarks?')){StorageManager.set('peh_bookmarks',[]);BookmarkManager.renderBookmarksPage();}break;case 'planner-add':PlannerManager.add($('#planner-title')?.value||'', $('#planner-chapter')?.value||StorageManager.get('peh_activeHub','bn'));if($('#planner-title'))$('#planner-title').value='';break;case 'planner-toggle':PlannerManager.toggle(unattr(target.dataset.id));break;case 'planner-delete':PlannerManager.remove(unattr(target.dataset.id));break;case 'planner-clear-done':StorageManager.set('peh_planner',PlannerManager.getAll().filter(item=>!item.done));PlannerManager.renderList();break;case 'mistake-remove':MistakeManager.remove(unattr(target.dataset.id));break;case 'mistake-clear':MistakeManager.clear();break;case 'revision-filter':RevisionHub.filter(target.dataset.hub);break;case 'dictionary-add':DictionaryManager.add($('#dictionary-word')?.value||'', $('#dictionary-meaning')?.value||'', $('#dictionary-sentence')?.value||'');['dictionary-word','dictionary-meaning','dictionary-sentence'].forEach(id=>{if($(`#${id}`))$(`#${id}`).value='';});break;case 'dictionary-remove':DictionaryManager.remove(unattr(target.dataset.id));break;case 'dictionary-clear':DictionaryManager.clear();break;case 'dictionary-speak':TTSEngine.speak(unattr(target.dataset.word),'en-IN');break;case 'notes-bold':NotesManager.formatBold();break;case 'notes-italic':NotesManager.formatItalic();break;case 'notes-bullet':NotesManager.formatBullet();break;case 'notes-heading':NotesManager.formatHeading();break;case 'notes-copy':NotesManager.copySelection();break;case 'notes-cut':NotesManager.cutSelection();break;case 'print-notes':NotesManager.printNotes();break;case 'clear-notes':NotesManager.clear();break;case 'pomodoro-toggle':PomodoroTimer.running?PomodoroTimer.pause():PomodoroTimer.start();break;case 'pomodoro-reset':PomodoroTimer.reset();break;case 'pomodoro-length':{const data=StorageManager.get('peh_pomodoro',DEFAULTS.peh_pomodoro);data.customDuration=Number(target.dataset.minutes);StorageManager.set('peh_pomodoro',data);PomodoroTimer.duration=data.customDuration*60;PomodoroTimer.remaining=PomodoroTimer.duration;PomodoroTimer.pause();PomodoroTimer.updateDisplay();break;}case 'canvas-pen':DrawingCanvas.pen();break;case 'canvas-eraser':DrawingCanvas.erase();break;case 'canvas-undo':DrawingCanvas.undo();break;case 'canvas-redo':DrawingCanvas.redo();break;case 'canvas-clear':DrawingCanvas.clear();break;case 'canvas-save':DrawingCanvas.saveAsPNG();break;case 'pronounce-input':TTSEngine.speak($('#pronounce-input')?.value||'accommodation','en-IN');break;case 'daily-answer':DailyChallenge.handleAnswer(target.dataset.option);break;case 'search-go':event.preventDefault();SearchEngine.navigateToResult(target.dataset.hub,target.dataset.chapter,unattr(target.dataset.anchor));break;default:break;}});document.addEventListener('change',event=>{if(event.target.id==='quiz-timed')QuizEngine.setTimed(event.target.checked);if(event.target.id==='bookmark-hub')BookmarkManager.filterBookmarks();if(event.target.dataset.action==='canvas-color')DrawingCanvas.setColor(event.target.value);if(event.target.dataset.action==='canvas-size')DrawingCanvas.setBrushSize(event.target.value);});document.addEventListener('input',event=>{if(event.target.id==='bookmark-search')BookmarkManager.filterBookmarks();if(event.target.dataset.action==='vocab-filter')renderTableFilter(event.target.dataset.table,event.target.value);if(event.target.id==='page-search')SearchEngine.renderPageResults(event.target.value);if(event.target.id==='dictionary-search')DictionaryManager.renderList(event.target.value);});$('#theme-toggle').addEventListener('click',()=>ThemeManager.toggle());$$('.font-button').forEach(button=>button.addEventListener('click',()=>{if(button.dataset.font==='increase')FontSizeManager.increase();else if(button.dataset.font==='decrease')FontSizeManager.decrease();else{StorageManager.set('peh_fontSize','normal');FontSizeManager.apply('normal');}}));$('#drawer-toggle').addEventListener('click',()=>$('#mobile-drawer').classList.contains('is-open')?closeDrawer():openDrawer());$('#drawer-scrim').addEventListener('click',closeDrawer);document.addEventListener('keydown',event=>{if(event.key==='Escape'){closeModal();closeDrawer();SettingsManager.close();NotesManager.close();}if(event.key==='?'&&!['INPUT','TEXTAREA','SELECT'].includes(document.activeElement.tagName)){event.preventDefault();showShortcutsModal();}if($('#flashcard')){if(event.code==='Space'){event.preventDefault();FlashcardEngine.flip();}if(event.key==='ArrowRight')FlashcardEngine.next();if(event.key==='ArrowLeft')FlashcardEngine.prev();if(event.key.toLowerCase()==='r')FlashcardEngine.markAgain();}});}

function init(){StorageManager.init();ThemeManager.init();FontSizeManager.init();HubSwitcher.init();GamificationEngine.init();Preloader.init();CustomCursor.init();ReadingProgressBar.init();NavShrink.init();SearchEngine.init();BookmarkManager.init();PomodoroTimer.init();NotesManager.init();SettingsManager.init();FocusManager.init();NavigationControls.init();BackToTop.init();RippleEffect.init();eventHub();Router.init();document.addEventListener('visibilitychange',()=>{if(document.hidden&&PomodoroTimer.running)PomodoroTimer.pause();});}
